fn browser_mode_instruction(mode: &str) -> String {
    let normalized = mode.to_ascii_lowercase().replace(['_', ' '], "-");
    match normalized.as_str() {
        "local" | "local-chrome" => concat!(
            "Selected browser mode: Local Chrome. Use `browser connect local` before page work. ",
            "This checks for a local Chromium-family browser exposing CDP and attaches only after remote debugging is enabled. ",
            "If connection is blocked, run `browser local setup` and wait for the user to approve remote debugging."
        )
        .to_string(),
        "headless" | "headless-chromium" | "managed-headless" => concat!(
            "Selected browser mode: Headless Chromium. Use `browser connect managed --headless` before page work. ",
            "This starts a Rust-owned managed browser with an isolated automation profile."
        )
        .to_string(),
        "managed" | "managed-headed" => concat!(
            "Selected browser mode: managed headed browser. Use `browser connect managed --headed` before page work. ",
            "This starts a Rust-owned visible browser with an isolated automation profile."
        )
        .to_string(),
        "cloud" | "browser-use-cloud" => concat!(
            "Selected browser mode: Browser Use cloud. Use `browser remote start` before page work. ",
            "Remote start means start and connect; use `browser remote live-url` to retrieve the watch URL."
        )
        .to_string(),
        other => format!(
            "Selected browser mode: {other}. Use `browser status --json` first, then choose an explicit browser connect command."
        ),
    }
}

fn collaboration_mode_instructions(mode: CollaborationModeKind) -> String {
    let template = match mode {
        CollaborationModeKind::Default => {
            include_str!("../../../prompts/collaboration-mode-default.md")
        }
        CollaborationModeKind::Plan => include_str!("../../../prompts/collaboration-mode-plan.md"),
    };
    let text = template.replace("{{KNOWN_MODE_NAMES}}", "Default and Plan");
    format!("{COLLABORATION_MODE_OPEN_TAG}{text}{COLLABORATION_MODE_CLOSE_TAG}")
}

fn collaboration_context_message(text: String) -> Value {
    serde_json::json!({
        "role": "developer",
        "name": COLLABORATION_CONTEXT_MESSAGE_NAME,
        "content": [{
            "type": "input_text",
            "text": text,
        }],
    })
}

fn latest_collaboration_mode_from_events(events: &[EventRecord]) -> Option<CollaborationModeKind> {
    events.iter().rev().find_map(|event| {
        if event.event_type != SESSION_COLLABORATION_MODE_EVENT {
            return None;
        }
        match event.payload.get("mode").and_then(Value::as_str)? {
            "plan" => Some(CollaborationModeKind::Plan),
            "default" => Some(CollaborationModeKind::Default),
            _ => None,
        }
    })
}

fn split_proposed_plan_blocks(text: &str) -> (String, Option<String>) {
    let mut visible = String::new();
    let mut latest_plan = None;
    let mut current_plan = String::new();
    let mut in_plan = false;
    let mut saw_plan = false;

    for line in text.split_inclusive('\n') {
        let line_without_newline = line.strip_suffix('\n').unwrap_or(line);
        let slug = line_without_newline.trim_start().trim_end();
        if !in_plan && slug == PROPOSED_PLAN_OPEN_TAG {
            in_plan = true;
            saw_plan = true;
            current_plan.clear();
            continue;
        }
        if in_plan && slug == PROPOSED_PLAN_CLOSE_TAG {
            in_plan = false;
            latest_plan = Some(current_plan.clone());
            continue;
        }
        if in_plan {
            current_plan.push_str(line);
        } else {
            visible.push_str(line);
        }
    }

    if in_plan && saw_plan {
        latest_plan = Some(current_plan);
    }
    (visible, latest_plan)
}

mod memory_citations;
pub(crate) use memory_citations::*;

fn strip_hidden_assistant_markup_for_stream(
    text: &str,
    mode: CollaborationModeKind,
) -> (String, Option<String>) {
    let (visible, proposed_plan) = strip_hidden_assistant_markup(text, mode);
    (
        trim_partial_hidden_assistant_tag_suffix(&visible, mode),
        proposed_plan,
    )
}

fn trim_partial_hidden_assistant_tag_suffix(text: &str, mode: CollaborationModeKind) -> String {
    let tags: &[&str] = if mode == CollaborationModeKind::Plan {
        &[OAI_MEMORY_CITATION_OPEN_TAG, PROPOSED_PLAN_OPEN_TAG]
    } else {
        &[OAI_MEMORY_CITATION_OPEN_TAG]
    };
    for (idx, _) in text.char_indices() {
        let suffix = &text[idx..];
        if tags
            .iter()
            .any(|tag| suffix.len() < tag.len() && tag.starts_with(suffix))
        {
            return text[..idx].to_string();
        }
    }
    text.to_string()
}

#[derive(Clone, Debug)]
struct HiddenAssistantMarkupStreamFilter {
    mode: CollaborationModeKind,
    raw_text: String,
    visible_text: String,
}

impl HiddenAssistantMarkupStreamFilter {
    fn new(mode: CollaborationModeKind) -> Self {
        Self {
            mode,
            raw_text: String::new(),
            visible_text: String::new(),
        }
    }

    fn push_provider_text(&mut self, incoming: &str) -> Option<(String, Option<String>)> {
        let raw_delta = assistant_delta_to_append(&self.raw_text, incoming)?;
        self.raw_text.push_str(&raw_delta);
        let visible = strip_hidden_assistant_markup_for_stream(&self.raw_text, self.mode).0;
        let visible_delta = assistant_delta_to_append(&self.visible_text, &visible);
        if let Some(delta) = visible_delta.as_deref() {
            self.visible_text.push_str(delta);
        }
        Some((raw_delta, visible_delta))
    }
}

fn strip_hidden_assistant_markup(
    text: &str,
    mode: CollaborationModeKind,
) -> (String, Option<String>) {
    let without_citations = strip_memory_citations(text);
    if mode == CollaborationModeKind::Plan {
        split_proposed_plan_blocks(&without_citations)
    } else {
        (without_citations, None)
    }
}

fn visible_assistant_text_and_proposed_plan(
    text: &str,
    mode: CollaborationModeKind,
) -> (String, Option<String>) {
    strip_hidden_assistant_markup(text, mode)
}

pub fn append_workspace_context_event(store: &Store, session: &SessionMeta) -> Result<bool> {
    append_workspace_context_event_with_options(store, session, &AgentRunOptions::default())
}

pub fn append_user_shell_command_context_event(
    store: &Store,
    session_id: &str,
    command: &str,
    exit_code: i32,
    duration: Duration,
    output: &str,
) -> Result<()> {
    let output = user_shell_context_output(output);
    let content = format!(
        "<user_shell_command>\n<command>\n{}\n</command>\n<result>\nExit code: {}\nDuration: {:.4} seconds\nOutput:\n{}\n</result>\n</user_shell_command>",
        command,
        exit_code,
        duration.as_secs_f64(),
        output,
    );
    store.append_event(
        session_id,
        "workspace.context",
        serde_json::json!({
            "kind": WORKSPACE_CONTEXT_USER_SHELL_KIND,
            "content": content,
            "command": command,
            "exit_code": exit_code,
            "duration_ms": duration.as_millis() as u64,
        }),
    )?;
    Ok(())
}

fn user_shell_context_output(output: &str) -> String {
    const MAX_USER_SHELL_CONTEXT_CHARS: usize = 40_000;
    let char_count = output.chars().count();
    if char_count <= MAX_USER_SHELL_CONTEXT_CHARS {
        return output.to_string();
    }
    let head_budget = MAX_USER_SHELL_CONTEXT_CHARS / 2;
    let tail_budget = MAX_USER_SHELL_CONTEXT_CHARS.saturating_sub(head_budget);
    let head = output.chars().take(head_budget).collect::<String>();
    let tail = output
        .chars()
        .rev()
        .take(tail_budget)
        .collect::<Vec<_>>()
        .into_iter()
        .rev()
        .collect::<String>();
    format!(
        "{head}\n[... omitted {} characters from user shell output ...]\n{tail}",
        char_count.saturating_sub(head_budget + tail_budget)
    )
}

pub fn review_prompt_uncommitted_changes() -> String {
    "Review the current code changes (staged, unstaged, and untracked files) and provide prioritized findings.".to_string()
}

pub fn review_prompt_base_branch(cwd: &Path, branch: &str) -> String {
    let branch = branch.trim();
    if branch.is_empty() {
        return review_prompt_uncommitted_changes();
    }
    if let Some(merge_base) = git_merge_base_with_head(cwd, branch) {
        format!(
            "Review the code changes against the base branch '{branch}'. The merge base commit for this comparison is {merge_base}. Run `git diff {merge_base}` to inspect the changes relative to {branch}. Provide prioritized, actionable findings."
        )
    } else {
        format!(
            "Review the code changes against the base branch '{branch}'. Start by finding the merge diff between the current branch and {branch}'s upstream e.g. (`git merge-base HEAD \"$(git rev-parse --abbrev-ref \"{branch}@{{upstream}}\")\"`), then run `git diff` against that SHA to see what changes we would merge into the {branch} branch. Provide prioritized, actionable findings."
        )
    }
}

pub fn review_prompt_commit(cwd: &Path, sha: &str) -> String {
    let sha = sha.trim();
    let title = git_commit_title(cwd, sha);
    if let Some(title) = title.filter(|title| !title.trim().is_empty()) {
        format!("Review the code changes introduced by commit {sha} (\"{title}\"). Provide prioritized, actionable findings.")
    } else {
        format!("Review the code changes introduced by commit {sha}. Provide prioritized, actionable findings.")
    }
}

pub fn review_prompt_custom(instructions: &str) -> Result<String> {
    let instructions = instructions.trim();
    if instructions.is_empty() {
        bail!("Review prompt cannot be empty");
    }
    Ok(instructions.to_string())
}

pub fn review_base_instructions() -> &'static str {
    include_str!("../../../prompts/review-prompt.md")
}

pub fn start_review_session(store: &Store, prompt: &str, cwd: impl AsRef<Path>) -> Result<String> {
    let cwd = cwd.as_ref();
    let session = store.create_session(None, cwd)?;
    store.append_event(
        &session.id,
        SESSION_REVIEW_MODE_EVENT,
        serde_json::json!({
            "kind": "review",
            "review_tool_restrictions": {
                "goals": false,
                "multi_agent": false,
                "web_search": false,
                "image_generation": false
            },
        }),
    )?;
    append_session_base_instructions_event(
        store,
        &session.id,
        review_base_instructions(),
        "review",
    )?;
    let options = review_mode_options(AgentRunOptions::default());
    append_workspace_context_event_with_options(store, &session, &options)?;
    store.append_event(
        &session.id,
        "session.input",
        typed_user_input_payload_from_text_for_cwd(prompt, cwd)?,
    )?;
    Ok(session.id)
}

fn review_mode_options(mut options: AgentRunOptions) -> AgentRunOptions {
    if options.base_instructions.is_none() {
        options.base_instructions = Some(review_base_instructions().to_string());
    }
    for (key, value) in [
        ("features.goals", toml::Value::Boolean(false)),
        ("features.multi_agent", toml::Value::Boolean(false)),
        (
            "features.multi_agent_v2.enabled",
            toml::Value::Boolean(false),
        ),
        ("features.web_search_cached", toml::Value::Boolean(false)),
        ("features.web_search_request", toml::Value::Boolean(false)),
        ("features.image_generation", toml::Value::Boolean(false)),
    ] {
        if !options
            .config_overrides
            .iter()
            .any(|(existing, _)| existing == key)
        {
            options.config_overrides.push((key.to_string(), value));
        }
    }
    options
}

fn session_is_review_mode(events: &[EventRecord]) -> bool {
    events
        .iter()
        .any(|event| event.event_type == SESSION_REVIEW_MODE_EVENT)
}

fn git_merge_base_with_head(cwd: &Path, branch: &str) -> Option<String> {
    let output = std::process::Command::new("git")
        .arg("merge-base")
        .arg("HEAD")
        .arg(branch)
        .current_dir(cwd)
        .output()
        .ok()?;
    output
        .status
        .success()
        .then(|| String::from_utf8_lossy(&output.stdout).trim().to_string())
        .filter(|value| !value.is_empty())
}

fn git_commit_title(cwd: &Path, sha: &str) -> Option<String> {
    let output = std::process::Command::new("git")
        .arg("show")
        .arg("-s")
        .arg("--format=%s")
        .arg(sha)
        .current_dir(cwd)
        .output()
        .ok()?;
    output
        .status
        .success()
        .then(|| String::from_utf8_lossy(&output.stdout).trim().to_string())
        .filter(|value| !value.is_empty())
}

pub fn append_workspace_context_event_with_options(
    store: &Store,
    session: &SessionMeta,
    options: &AgentRunOptions,
) -> Result<bool> {
    let events = store.events_for_session(&session.id)?;
    let before_seq = current_turn_user_message_seq(&events);
    let has_context_kind = |kind: &str| {
        events.iter().any(|event| {
            event.event_type == "workspace.context"
                && event.payload.get("kind").and_then(Value::as_str) == Some(kind)
        })
    };
    let latest_context_content = |kind: &str| {
        events.iter().rev().find_map(|event| {
            (event.event_type == "workspace.context"
                && event.payload.get("kind").and_then(Value::as_str) == Some(kind))
            .then(|| event.payload.get("content").and_then(Value::as_str))
            .flatten()
        })
    };
    let latest_environment_snapshot = || latest_environment_snapshot_from_events(&events);
    let agents_context = if !has_context_kind(WORKSPACE_CONTEXT_AGENTS_KIND) {
        Some(load_agents_md_context_for_cwd_with_run_options(
            Path::new(&session.cwd),
            options,
        )?)
    } else {
        None
    };
    let mut appended = false;
    let config_developer_instructions = options
        .developer_instructions
        .as_deref()
        .or_else(|| {
            agents_context
                .as_ref()
                .and_then(|load| load.developer_instructions.as_deref())
        })
        .filter(|text| !text.is_empty())
        .map(str::to_string);
    let config_plugins_instructions = agents_context
        .as_ref()
        .and_then(|load| load.plugins_instructions.clone());
    let config_skills_instructions = agents_context
        .as_ref()
        .and_then(|load| load.skills_instructions.clone());
    let config_memory_instructions = agents_context
        .as_ref()
        .and_then(|load| load.memory_instructions.clone());
    let config_include_environment_context = agents_context
        .as_ref()
        .is_none_or(|load| load.include_environment_context);
    let config_include_permissions_instructions = options.include_permissions_instructions
        && agents_context
            .as_ref()
            .is_none_or(|load| load.include_permissions_instructions);
    let config_include_collaboration_mode_instructions = agents_context
        .as_ref()
        .is_none_or(|load| load.include_collaboration_mode_instructions);
    let collaboration_context = config_include_collaboration_mode_instructions
        .then(|| collaboration_mode_instructions(options.collaboration_mode));
    let multi_agent_v2_usage_hint =
        if !has_context_kind(WORKSPACE_CONTEXT_MULTI_AGENT_USAGE_HINT_KIND) {
            if let Some(agents_context) = agents_context.as_ref() {
                multi_agent_v2_usage_hint_text_for_session(
                    session,
                    agents_context.multi_agent_enabled,
                    &agents_context.multi_agent_v2,
                )
            } else {
                let mut warnings = Vec::new();
                let config = load_agents_md_config_for_options(
                    Path::new(&session.cwd),
                    &mut warnings,
                    options,
                )?;
                multi_agent_v2_usage_hint_text_for_session(
                    session,
                    config.multi_agent_enabled,
                    &config.multi_agent_v2,
                )
            }
        } else {
            None
        };
    let previous_collaboration_mode = latest_collaboration_mode_from_events(&events);
    if previous_collaboration_mode != Some(options.collaboration_mode) {
        store.append_event(
            &session.id,
            SESSION_COLLABORATION_MODE_EVENT,
            serde_json::json!({
                "mode": options.collaboration_mode.as_str(),
            }),
        )?;
        appended = true;
    }
    if !has_context_kind(WORKSPACE_CONTEXT_PERMISSIONS_KIND) {
        let mut developer_sections = Vec::new();
        if config_include_permissions_instructions {
            developer_sections.push(default_permissions_instructions().to_string());
        }
        if let Some(developer_instructions) = config_developer_instructions {
            developer_sections.push(developer_instructions);
        }
        if let Some(collaboration_context) = collaboration_context.as_ref() {
            developer_sections.push(collaboration_context.clone());
        }
        if let Some(memory_instructions) = config_memory_instructions {
            developer_sections.push(memory_instructions);
        }
        if let Some(skills_instructions) = config_skills_instructions {
            developer_sections.push(skills_instructions);
        }
        if let Some(plugins_instructions) = config_plugins_instructions {
            developer_sections.push(plugins_instructions);
        }
        let payload = if developer_sections.is_empty() {
            serde_json::json!({
                "kind": WORKSPACE_CONTEXT_PERMISSIONS_KIND,
                "suppressed": true,
            })
        } else {
            serde_json::json!({
                "kind": WORKSPACE_CONTEXT_PERMISSIONS_KIND,
                "content": developer_sections.join("\n\n"),
                "permissions_instructions_included": config_include_permissions_instructions,
            })
        };
        store.append_event(&session.id, "workspace.context", payload)?;
        appended = true;
    } else if let Some(collaboration_context) = collaboration_context.as_ref() {
        let latest_collaboration_context = events.iter().rev().find_map(|event| {
            (event.event_type == COLLABORATION_CONTEXT_EVENT)
                .then(|| event.payload.get("content").and_then(Value::as_str))
                .flatten()
        });
        let permissions_contains_current_mode = events.iter().any(|event| {
            event.event_type == "workspace.context"
                && event.payload.get("kind").and_then(Value::as_str)
                    == Some(WORKSPACE_CONTEXT_PERMISSIONS_KIND)
                && event
                    .payload
                    .get("content")
                    .and_then(Value::as_str)
                    .is_some_and(|content| content.contains(collaboration_context.as_str()))
        });
        let current_mode_is_only_in_initial_permissions = latest_collaboration_context.is_none()
            && permissions_contains_current_mode
            && previous_collaboration_mode == Some(options.collaboration_mode);
        if latest_collaboration_context != Some(collaboration_context.as_str())
            && !current_mode_is_only_in_initial_permissions
        {
            let mut payload = serde_json::json!({
                "mode": options.collaboration_mode.as_str(),
                "content": collaboration_context,
            });
            if let Some(before_seq) = before_seq {
                payload["before_seq"] = serde_json::json!(before_seq);
            }
            store.append_event(&session.id, COLLABORATION_CONTEXT_EVENT, payload)?;
            appended = true;
        }
    }
    if let Some(multi_agent_v2_usage_hint) = multi_agent_v2_usage_hint {
        store.append_event(
            &session.id,
            "workspace.context",
            serde_json::json!({
                "kind": WORKSPACE_CONTEXT_MULTI_AGENT_USAGE_HINT_KIND,
                "content": multi_agent_v2_usage_hint,
            }),
        )?;
        appended = true;
    }
    if let Some(agents_context) = agents_context {
        let AgentsMdLoad {
            context,
            sources,
            warnings,
            skills_instructions: _,
            ..
        } = agents_context;
        if context.is_some() || !sources.is_empty() || !warnings.is_empty() {
            let mut payload = serde_json::json!({
                "kind": WORKSPACE_CONTEXT_AGENTS_KIND,
                "sources": sources.clone(),
                "warnings": warnings.clone(),
            });
            if let Some(content) = context.as_ref().map(|context| &context.content) {
                payload["content"] = Value::String(content.clone());
            }
            store.append_event(&session.id, "workspace.context", payload)?;
            appended = true;
        }
        if !sources.is_empty() {
            store.append_event(
                &session.id,
                SESSION_INSTRUCTION_SOURCES_EVENT,
                serde_json::json!({
                    "source": "agents_md",
                    "sources": sources.clone(),
                }),
            )?;
            appended = true;
        }
        for warning in warnings {
            store.append_event(
                &session.id,
                SESSION_STARTUP_WARNING_EVENT,
                serde_json::json!({
                    "source": "agents_md",
                    "message": warning,
                }),
            )?;
            appended = true;
        }
    }
    if options.include_environment_context && config_include_environment_context {
        let environment_snapshot =
            environment_context_snapshot_for_session(store, session, options)?;
        let environment_context = render_environment_context_snapshot(&environment_snapshot);
        let previous_environment_snapshot = latest_environment_snapshot();
        let compare_subagents = before_seq.is_none();
        let should_append = previous_environment_snapshot.as_ref().map_or_else(
            || {
                latest_context_content(WORKSPACE_CONTEXT_ENVIRONMENT_KIND)
                    != Some(environment_context.as_str())
            },
            |previous| {
                !environment_context_equals_except_shell(
                    previous,
                    &environment_snapshot,
                    compare_subagents,
                )
            },
        );
        if should_append {
            let content = if let (Some(previous), Some(_)) =
                (previous_environment_snapshot.as_ref(), before_seq)
            {
                render_environment_context_update(previous, &environment_snapshot)
            } else {
                environment_context
            };
            let mut payload = serde_json::json!({
                "kind": WORKSPACE_CONTEXT_ENVIRONMENT_KIND,
                "content": content,
                "environment": environment_snapshot,
            });
            if let Some(before_seq) = before_seq {
                payload["before_seq"] = serde_json::json!(before_seq);
            }
            store.append_event(&session.id, "workspace.context", payload)?;
            appended = true;
        }
    } else if has_context_kind(WORKSPACE_CONTEXT_ENVIRONMENT_KIND) {
        let mut payload = serde_json::json!({
            "kind": WORKSPACE_CONTEXT_ENVIRONMENT_KIND,
            "content": "",
        });
        if let Some(before_seq) = before_seq {
            payload["before_seq"] = serde_json::json!(before_seq);
        }
        store.append_event(&session.id, "workspace.context", payload)?;
        appended = true;
    }
    Ok(appended)
}

fn multi_agent_v2_usage_hint_text_for_session(
    session: &SessionMeta,
    multi_agent_enabled: bool,
    config: &MultiAgentV2Config,
) -> Option<String> {
    if !multi_agent_enabled {
        return None;
    }
    let hint = if session.parent_id.is_some() {
        config.subagent_usage_hint_text.as_deref()
    } else {
        config.root_agent_usage_hint_text.as_deref()
    }?;
    (!hint.trim().is_empty()).then(|| hint.to_string())
}

pub fn run_fake_agent(
    store: &Store,
    task_text: &str,
    cwd: impl AsRef<Path>,
    options: FakeAgentOptions<'_>,
) -> Result<String> {
    let provider = if let Some(code) = options.python_code {
        ScriptedProvider::new(vec![
            vec![
                ModelEvent::TextDelta {
                    text: "Starting browser task.\n".to_string(),
                },
                ModelEvent::ToolCall {
                    call: ToolCall {
                        id: "call_python".to_string(),
                        name: "python".to_string(),
                        namespace: None,
                        arguments: serde_json::json!({ "code": code }),
                    },
                },
                ModelEvent::Done,
            ],
            vec![
                ModelEvent::ToolCall {
                    call: ToolCall {
                        id: "call_done".to_string(),
                        name: "done".to_string(),
                        namespace: None,
                        arguments: serde_json::json!({
                            "result": "Python tool completed."
                        }),
                    },
                },
                ModelEvent::Done,
            ],
        ])
    } else {
        ScriptedProvider::new(vec![vec![
            ModelEvent::TextDelta {
                text: format!("Fake result for: {task_text}"),
            },
            ModelEvent::Done,
        ]])
    };
    run_agent_with_provider(store, &provider, task_text, cwd, AgentRunOptions::default())
}

pub fn run_agent_with_provider<P: ModelProvider>(
    store: &Store,
    provider: &P,
    task_text: &str,
    cwd: impl AsRef<Path>,
    options: AgentRunOptions,
) -> Result<String> {
    let session = store.create_session(None, cwd.as_ref())?;
    append_workspace_context_event_with_options(store, &session, &options)?;
    store.append_event(
        &session.id,
        "session.input",
        typed_user_input_payload_from_text_for_cwd(task_text, cwd.as_ref())?,
    )?;
    let messages = provider_messages_from_events(&store.events_for_session(&session.id)?);
    run_loaded_session_with_provider(store, provider, session, messages, options)
}

pub fn run_agent_from_config(
    store: &Store,
    task_text: &str,
    cwd: impl AsRef<Path>,
    config: ProviderRunConfig,
) -> Result<String> {
    let session = store.create_session(None, cwd.as_ref())?;
    append_workspace_context_event_with_options(store, &session, &config.options)?;
    store.append_event(
        &session.id,
        "session.input",
        typed_user_input_payload_from_text_for_cwd(task_text, cwd.as_ref())?,
    )?;
    run_existing_session_from_config(store, &session.id, config)
}

pub fn run_existing_session_with_provider<P: ModelProvider>(
    store: &Store,
    provider: &P,
    session_id: &str,
    mut options: AgentRunOptions,
) -> Result<String> {
    let session = store
        .load_session(session_id)?
        .with_context(|| format!("unknown session id: {session_id}"))?;
    let events = store.events_for_session(session_id)?;
    if session_is_review_mode(&events) {
        options = review_mode_options(options);
    }
    append_workspace_context_event_with_options(store, &session, &options)?;
    let events = store.events_for_session(session_id)?;
    let messages = provider_messages_from_events(&events);
    run_loaded_session_with_provider(store, provider, session, messages, options)
}

pub fn run_existing_session_from_config(
    store: &Store,
    session_id: &str,
    mut config: ProviderRunConfig,
) -> Result<String> {
    let provider_kind = provider_backend_kind(config.backend).to_string();
    let session = store
        .load_session(session_id)?
        .with_context(|| format!("unknown session id: {session_id}"))?;
    let existing_events = store.events_for_session(&session.id)?;
    let review_mode = session_is_review_mode(&existing_events);
    if review_mode {
        config.options = review_mode_options(config.options);
    }
    let config_snapshot = latest_session_config_snapshot_from_events(&existing_events);
    if let Some(snapshot) = config_snapshot
        .as_ref()
        .filter(|_| !run_config_has_model_resume_override(&config))
    {
        if config.model_source == RunConfigValueSource::Default {
            config.model = snapshot.model.clone();
        }
        if config.options.model_provider_id_source == RunConfigValueSource::Default {
            config.options.model_provider_id = Some(snapshot.model_provider_id.clone());
        }
    }
    let provider_config = load_provider_config_for_session(&session, &config.options)?;
    let selected_provider_id = config
        .options
        .model_provider_id
        .clone()
        .or(provider_config.model_provider_id.clone())
        .unwrap_or_else(|| provider_kind.clone());
    let snapshot_provider_info = config_snapshot
        .as_ref()
        .filter(|_| !run_config_has_model_resume_override(&config))
        .and_then(|snapshot| snapshot.model_provider_info.as_ref())
        .filter(|provider_info| provider_info.id == selected_provider_id)
        .filter(|_| should_use_snapshot_provider_runtime_config(&config.options));
    if selected_provider_id != provider_kind
        && !provider_config
            .model_providers
            .contains_key(&selected_provider_id)
        && snapshot_provider_info.is_none()
    {
        bail!(
            "Model provider `{selected_provider_id}` is not available for `{provider_kind}` runs"
        );
    }
    if review_mode && config.model_source == RunConfigValueSource::Default {
        let mut warnings = Vec::new();
        let review_config = load_agents_md_config_for_options(
            Path::new(&session.cwd),
            &mut warnings,
            &config.options,
        )?;
        if let Some(review_model) = review_config.review_model.as_ref() {
            config.model = review_model.clone();
        }
    }
    config.options.model_provider_id = Some(selected_provider_id.clone());
    install_config_child_agent_runner(store, &mut config);
    config.options.analytics_provider_kind = Some(provider_kind);
    config.options.analytics_model = Some(config.model.clone());
    match config.backend {
        ProviderBackend::Codex => {
            if let Some(provider_info) = snapshot_provider_info {
                if provider_info.wire_api == "chat" {
                    let provider = configured_openai_chat_provider_from_snapshot(
                        store,
                        config.model.clone(),
                        provider_info,
                    )?;
                    return run_existing_session_with_provider(
                        store,
                        &provider,
                        session_id,
                        config.options,
                    );
                } else {
                    let provider = configured_openai_responses_provider_from_snapshot(
                        store,
                        config.model.clone(),
                        provider_info,
                    )?;
                    return run_existing_session_with_provider(
                        store,
                        &provider,
                        session_id,
                        config.options,
                    );
                }
            }
            if let Some(provider) = configured_openai_responses_provider(
                store,
                config.model.clone(),
                &provider_config,
                &selected_provider_id,
            )? {
                return run_existing_session_with_provider(
                    store,
                    &provider,
                    session_id,
                    config.options,
                );
            }
            if let Some(provider) = configured_openai_chat_provider(
                store,
                config.model.clone(),
                &provider_config,
                &selected_provider_id,
            )? {
                return run_existing_session_with_provider(
                    store,
                    &provider,
                    session_id,
                    config.options,
                );
            }
            let provider = codex_provider(store, config.model)?;
            run_existing_session_with_provider(store, &provider, session_id, config.options)
        }
        ProviderBackend::Openai => {
            if let Some(provider_info) = snapshot_provider_info {
                if provider_info.wire_api == "chat" {
                    let provider = configured_openai_chat_provider_from_snapshot(
                        store,
                        config.model.clone(),
                        provider_info,
                    )?;
                    return run_existing_session_with_provider(
                        store,
                        &provider,
                        session_id,
                        config.options,
                    );
                }
                let provider = configured_openai_responses_provider_from_snapshot(
                    store,
                    config.model.clone(),
                    provider_info,
                )?;
                return run_existing_session_with_provider(
                    store,
                    &provider,
                    session_id,
                    config.options,
                );
            }
            if let Some(provider) = configured_openai_responses_provider(
                store,
                config.model.clone(),
                &provider_config,
                &selected_provider_id,
            )? {
                run_existing_session_with_provider(store, &provider, session_id, config.options)
            } else if let Some(provider) = configured_openai_chat_provider(
                store,
                config.model.clone(),
                &provider_config,
                &selected_provider_id,
            )? {
                run_existing_session_with_provider(store, &provider, session_id, config.options)
            } else {
                let provider = openai_provider(store, config.model)?;
                run_existing_session_with_provider(store, &provider, session_id, config.options)
            }
        }
        ProviderBackend::Anthropic => {
            let provider = anthropic_provider(store, config.model)?;
            run_existing_session_with_provider(store, &provider, session_id, config.options)
        }
        ProviderBackend::Openrouter => {
            let provider = openrouter_provider(store, config.model)?;
            run_existing_session_with_provider(store, &provider, session_id, config.options)
        }
        ProviderBackend::Deepseek => {
            let provider = deepseek_provider(store, config.model)?;
            run_existing_session_with_provider(store, &provider, session_id, config.options)
        }
        ProviderBackend::Fake => {
            let provider = FakeProvider::with_text(
                config
                    .fake_result
                    .as_deref()
                    .unwrap_or("Fake browser task completed."),
            );
            run_existing_session_with_provider(store, &provider, session_id, config.options)
        }
        ProviderBackend::None => Ok(session_id.to_string()),
    }
}

fn provider_backend_kind(backend: ProviderBackend) -> &'static str {
    match backend {
        ProviderBackend::Codex => "codex",
        ProviderBackend::Openai => "openai",
        ProviderBackend::Anthropic => "anthropic",
        ProviderBackend::Openrouter => "openrouter",
        ProviderBackend::Deepseek => "deepseek",
        ProviderBackend::Fake => "fake",
        ProviderBackend::None => "none",
    }
}

