fn run_pre_tool_use_hooks(
    store: &Store,
    session: &SessionMeta,
    hooks: &RuntimeHookConfig,
    model: &str,
    call: &ToolCall,
    tool_output_token_budget: usize,
    turn_idx: usize,
) -> Result<Option<PreToolUseHookDecision>> {
    let hook_tool_input = hook_visible_tool_input(call);
    let mut outcome = run_hooks_for_event(
        store,
        session,
        hooks,
        HookEventName::PreToolUse,
        Some(call),
        None,
        Some(&hook_tool_input),
        model,
        serde_json::json!({ "turn_idx": turn_idx }),
    )?;
    if let Some(updated_input) = outcome.updated_input.as_ref() {
        outcome.updated_input = Some(hook_updated_input_to_tool_arguments(call, updated_input));
    }
    if outcome.updated_input.is_none()
        && outcome.additional_contexts.is_empty()
        && outcome.block_reason.is_none()
        && outcome.stop_reason.is_none()
    {
        return Ok(None);
    }
    let mut context_messages = outcome
        .additional_contexts
        .into_iter()
        .map(|context| hook_context_message(HookEventName::PreToolUse, &context))
        .collect::<Vec<_>>();
    if let Some(reason) = outcome.block_reason.or(outcome.stop_reason) {
        store.append_event(
            &session.id,
            "hook.blocked",
            serde_json::json!({
                "hook_event_name": HookEventName::PreToolUse.as_str(),
                "tool_name": call.name,
                "tool_call_id": call.id,
                "reason": reason,
            }),
        )?;
        context_messages.push(tool_text_message(
            store,
            session,
            call,
            &call.name,
            &format!("{} blocked by PreToolUse hook: {reason}", call.name),
            tool_output_token_budget,
        )?);
        return Ok(Some(PreToolUseHookDecision::Blocked(ToolDispatchOutcome {
            finished: false,
            messages: context_messages,
        })));
    }
    Ok(Some(PreToolUseHookDecision::Continue {
        updated_input: outcome.updated_input,
        context_messages,
    }))
}

fn run_post_tool_use_hooks(
    store: &Store,
    session: &SessionMeta,
    hooks: &RuntimeHookConfig,
    model: &str,
    call: &ToolCall,
    tool_output: &[Value],
    turn_idx: usize,
) -> Result<PostToolUseHookResult> {
    let outcome = run_hooks_for_event(
        store,
        session,
        hooks,
        HookEventName::PostToolUse,
        Some(call),
        None,
        None,
        model,
        serde_json::json!({
            "turn_idx": turn_idx,
            "tool_output": tool_output,
            "tool_response": tool_output,
        }),
    )?;
    let mut messages = outcome
        .additional_contexts
        .into_iter()
        .map(|context| hook_context_message(HookEventName::PostToolUse, &context))
        .collect::<Vec<_>>();
    let replacement_text = if !outcome.feedback_messages.is_empty() {
        Some(outcome.feedback_messages.join("\n"))
    } else {
        outcome
            .block_reason
            .clone()
            .or_else(|| outcome.stop_reason.clone())
    };
    if let Some(reason) = outcome.block_reason.or(outcome.stop_reason) {
        store.append_event(
            &session.id,
            "hook.blocked",
            serde_json::json!({
                "hook_event_name": HookEventName::PostToolUse.as_str(),
                "tool_name": call.name,
                "tool_call_id": call.id,
                "reason": reason,
            }),
        )?;
        messages.push(hook_context_message(
            HookEventName::PostToolUse,
            &format!("PostToolUse hook blocked continuation: {reason}"),
        ));
    }
    if let Some(replacement_text) = replacement_text.as_deref() {
        store.append_event(
            &session.id,
            "hook.feedback",
            serde_json::json!({
                "hook_event_name": HookEventName::PostToolUse.as_str(),
                "tool_name": call.name,
                "tool_call_id": call.id,
                "feedback": replacement_text,
            }),
        )?;
    }
    Ok(PostToolUseHookResult {
        context_messages: messages,
        replacement_text,
    })
}

struct PostToolUseHookResult {
    context_messages: Vec<Value>,
    replacement_text: Option<String>,
}

enum PreToolUseHookDecision {
    Continue {
        updated_input: Option<Value>,
        context_messages: Vec<Value>,
    },
    Blocked(ToolDispatchOutcome),
}

#[allow(clippy::too_many_arguments)]
fn run_hooks_for_event(
    store: &Store,
    session: &SessionMeta,
    hooks: &RuntimeHookConfig,
    event: HookEventName,
    call: Option<&ToolCall>,
    matcher_target: Option<&str>,
    tool_input: Option<&Value>,
    model: &str,
    extra: Value,
) -> Result<HookRunOutcome> {
    if hooks.is_empty() {
        return Ok(HookRunOutcome::default());
    }
    let mut invocations = Vec::new();
    for group in hooks.groups_for_event(event) {
        if !hook_group_matches(group, call, matcher_target) {
            continue;
        }
        for hook in &group.hooks {
            if hook.async_run {
                continue;
            }
            let configured_order = invocations.len();
            invocations.push(prepare_command_hook_run(
                store,
                session,
                event,
                call,
                tool_input,
                model,
                extra.clone(),
                hook,
                configured_order,
            )?);
        }
    }
    let outcome = run_prepared_command_hooks(store, session, event, call, invocations)?;
    Ok(outcome)
}

#[derive(Debug)]
struct PreparedCommandHookRun {
    configured_order: usize,
    hook_id: String,
    command: String,
    cwd: String,
    input: Value,
    timeout: Option<Duration>,
    async_run: bool,
    status_message: Option<String>,
    source: HookSourceMetadata,
    state_key: String,
    display_order: i64,
    trusted_hash: Option<String>,
    started_at_ms: i64,
    transcript_path: Option<String>,
}

struct CompletedCommandHookRun {
    configured_order: usize,
    completion_order: usize,
    hook_id: String,
    command: String,
    async_run: bool,
    status_message: Option<String>,
    source: HookSourceMetadata,
    state_key: String,
    display_order: i64,
    trusted_hash: Option<String>,
    started_at_ms: i64,
    completed_at_ms: i64,
    transcript_path: Option<String>,
    result: std::result::Result<HookProcessOutput, String>,
}

#[allow(clippy::too_many_arguments)]
fn prepare_command_hook_run(
    store: &Store,
    session: &SessionMeta,
    event: HookEventName,
    call: Option<&ToolCall>,
    tool_input: Option<&Value>,
    model: &str,
    extra: Value,
    hook: &HookCommandConfig,
    configured_order: usize,
) -> Result<PreparedCommandHookRun> {
    let command = if cfg!(windows) {
        hook.command_windows
            .as_deref()
            .unwrap_or(&hook.command)
            .to_string()
    } else {
        hook.command.clone()
    };
    let hook_id = uuid::Uuid::new_v4().to_string();
    let started_at_ms = now_ms();
    let transcript_path =
        write_hook_transcript_snapshot(store, session, event, &hook_id, configured_order)
            .transpose()?
            .map(|path| path.display().to_string());
    let hook_input = hook_command_input_with_transcript(
        store,
        session,
        event,
        call,
        tool_input,
        model,
        extra,
        transcript_path.as_deref(),
    );
    let run = hook_run_summary_json(HookRunSummaryInput {
        hook_id: &hook_id,
        event,
        hook,
        command: &command,
        status: "running",
        started_at_ms,
        completed_at_ms: None,
        duration_ms: None,
        entries: Vec::new(),
    });
    store.append_event(
        &session.id,
        "hook.started",
        serde_json::json!({
            "turn_id": hook_input.get("turn_id").cloned().unwrap_or(Value::Null),
            "run": run,
            "hook_id": hook_id.clone(),
            "hook_event_name": event.as_str(),
            "tool_name": call.map(|call| call.name.as_str()),
            "tool_call_id": call.map(|call| call.id.as_str()),
            "command": command,
            "async": hook.async_run,
            "status_message": hook.status_message,
            "configured_order": configured_order,
            "display_order": hook.display_order,
            "source": hook.source.source.as_str(),
            "source_path": hook.source.path.clone(),
            "state_key": hook.state_key.clone(),
            "trusted_hash": hook.trusted_hash.clone(),
            "trust_status": hook_trust_status(&hook.source, hook.trusted_hash.as_deref()),
            "started_at": started_at_ms,
            "transcript_path": transcript_path.clone(),
        }),
    )?;
    Ok(PreparedCommandHookRun {
        configured_order,
        hook_id,
        command,
        cwd: session.cwd.clone(),
        input: hook_input,
        timeout: hook.timeout_sec.map(Duration::from_secs),
        async_run: hook.async_run,
        status_message: hook.status_message.clone(),
        source: hook.source.clone(),
        state_key: hook.state_key.clone(),
        display_order: hook.display_order,
        trusted_hash: hook.trusted_hash.clone(),
        started_at_ms,
        transcript_path,
    })
}

fn run_prepared_command_hooks(
    store: &Store,
    session: &SessionMeta,
    event: HookEventName,
    call: Option<&ToolCall>,
    invocations: Vec<PreparedCommandHookRun>,
) -> Result<HookRunOutcome> {
    if invocations.is_empty() {
        return Ok(HookRunOutcome::default());
    }

    let expected = invocations.len();
    let (tx, rx) = std::sync::mpsc::channel::<CompletedCommandHookRun>();
    let mut handles = Vec::with_capacity(expected);
    for invocation in invocations {
        let tx = tx.clone();
        handles.push(thread::spawn(move || {
            let result = run_hook_command_process(
                &invocation.cwd,
                &invocation.command,
                &invocation.input,
                invocation.timeout,
            )
            .map_err(|error| format!("{error:#}"));
            let _ = tx.send(CompletedCommandHookRun {
                configured_order: invocation.configured_order,
                completion_order: 0,
                hook_id: invocation.hook_id,
                command: invocation.command,
                async_run: invocation.async_run,
                status_message: invocation.status_message,
                source: invocation.source,
                state_key: invocation.state_key,
                display_order: invocation.display_order,
                trusted_hash: invocation.trusted_hash,
                started_at_ms: invocation.started_at_ms,
                completed_at_ms: now_ms(),
                transcript_path: invocation.transcript_path,
                result,
            });
        }));
    }
    drop(tx);

    let mut completed = Vec::with_capacity(expected);
    for completion_order in 0..expected {
        let mut run = rx
            .recv()
            .context("hook command worker exited without reporting a result")?;
        run.completion_order = completion_order;
        completed.push(run);
    }
    for handle in handles {
        handle
            .join()
            .map_err(|_| anyhow!("hook command worker panicked"))?;
    }

    let mut parsed = Vec::with_capacity(completed.len());
    for run in completed {
        let outcome = finish_command_hook_run(store, session, event, call, &run)?;
        parsed.push((run.configured_order, run.completion_order, outcome));
    }
    parsed.sort_by_key(|(configured_order, _, _)| *configured_order);

    let mut outcome = HookRunOutcome::default();
    let mut latest_updated_input = None::<(usize, Value)>;
    for (_, completion_order, hook_outcome) in parsed {
        if let Some(updated_input) = hook_outcome.updated_input {
            let should_replace = match latest_updated_input.as_ref() {
                Some((latest_completion_order, _)) => completion_order >= *latest_completion_order,
                None => true,
            };
            if should_replace {
                latest_updated_input = Some((completion_order, updated_input));
            }
        }
        outcome
            .additional_contexts
            .extend(hook_outcome.additional_contexts);
        outcome
            .feedback_messages
            .extend(hook_outcome.feedback_messages);
        if outcome.block_reason.is_none() {
            outcome.block_reason = hook_outcome.block_reason;
        }
        if outcome.stop_reason.is_none() {
            outcome.stop_reason = hook_outcome.stop_reason;
        }
    }
    outcome.updated_input = latest_updated_input.map(|(_, updated_input)| updated_input);
    Ok(outcome)
}

fn finish_command_hook_run(
    store: &Store,
    session: &SessionMeta,
    event: HookEventName,
    call: Option<&ToolCall>,
    run: &CompletedCommandHookRun,
) -> Result<HookRunOutcome> {
    let duration_ms = run.completed_at_ms.saturating_sub(run.started_at_ms);
    let output = match &run.result {
        Ok(output) => output,
        Err(error) => {
            let entries = vec![hook_output_entry("error", error)];
            let run_summary = completed_hook_run_summary_json(
                event,
                run,
                "failed",
                Some(duration_ms),
                entries.clone(),
            );
            store.append_event(
                &session.id,
                "hook.failed",
                serde_json::json!({
                    "turn_id": active_request_user_input_turn_id(
                        &store.events_for_session(&session.id).unwrap_or_default(),
                        &session.id
                    ),
                    "run": run_summary,
                    "hook_id": run.hook_id.clone(),
                    "hook_event_name": event.as_str(),
                    "tool_name": call.map(|call| call.name.as_str()),
                    "tool_call_id": call.map(|call| call.id.as_str()),
                    "command": run.command.clone(),
                    "configured_order": run.configured_order,
                    "completion_order": run.completion_order,
                    "display_order": run.display_order,
                    "source": run.source.source.as_str(),
                    "source_path": run.source.path.clone(),
                    "state_key": run.state_key.clone(),
                    "trusted_hash": run.trusted_hash.clone(),
                    "trust_status": hook_trust_status(&run.source, run.trusted_hash.as_deref()),
                    "started_at": run.started_at_ms,
                    "completed_at": run.completed_at_ms,
                    "duration_ms": duration_ms,
                    "entries": entries,
                    "transcript_path": run.transcript_path.clone(),
                    "async": run.async_run,
                    "error": error,
                }),
            )?;
            return Ok(HookRunOutcome::default());
        }
    };
    let outcome = parse_hook_command_output(event, &output.stdout, &output.stderr, output.status);
    let status = hook_run_status_for_outcome(output.status, &outcome);
    let entries = hook_output_entries(&outcome, &output.stderr, output.status);
    let run_summary =
        completed_hook_run_summary_json(event, run, status, Some(duration_ms), entries.clone());
    store.append_event(
        &session.id,
        "hook.completed",
        serde_json::json!({
            "turn_id": active_request_user_input_turn_id(
                &store.events_for_session(&session.id).unwrap_or_default(),
                &session.id
            ),
            "run": run_summary,
            "hook_id": run.hook_id.clone(),
            "hook_event_name": event.as_str(),
            "tool_name": call.map(|call| call.name.as_str()),
            "tool_call_id": call.map(|call| call.id.as_str()),
            "command": run.command.clone(),
            "configured_order": run.configured_order,
            "completion_order": run.completion_order,
            "display_order": run.display_order,
            "source": run.source.source.as_str(),
            "source_path": run.source.path.clone(),
            "state_key": run.state_key.clone(),
            "trusted_hash": run.trusted_hash.clone(),
            "trust_status": hook_trust_status(&run.source, run.trusted_hash.as_deref()),
            "started_at": run.started_at_ms,
            "completed_at": run.completed_at_ms,
            "duration_ms": duration_ms,
            "entries": entries,
            "transcript_path": run.transcript_path.clone(),
            "status": output.status,
            "stdout": truncate_text_for_event(&output.stdout, 4000),
            "stderr": truncate_text_for_event(&output.stderr, 4000),
            "async": run.async_run,
        }),
    )?;
    Ok(outcome)
}

struct HookRunSummaryInput<'a> {
    hook_id: &'a str,
    event: HookEventName,
    hook: &'a HookCommandConfig,
    command: &'a str,
    status: &'a str,
    started_at_ms: i64,
    completed_at_ms: Option<i64>,
    duration_ms: Option<i64>,
    entries: Vec<Value>,
}

fn hook_run_summary_json(input: HookRunSummaryInput<'_>) -> Value {
    serde_json::json!({
        "id": input.hook_id,
        "event_name": input.event.as_str(),
        "handler_type": "command",
        "execution_mode": if input.hook.async_run { "async" } else { "sync" },
        "scope": hook_scope_for_event(input.event),
        "source_path": input.hook.source.path.clone(),
        "source": input.hook.source.source.as_str(),
        "display_order": input.hook.display_order,
        "status": input.status,
        "status_message": input.hook.status_message.clone(),
        "started_at": input.started_at_ms,
        "completed_at": input.completed_at_ms,
        "duration_ms": input.duration_ms,
        "entries": input.entries,
        "command": input.command,
        "state_key": input.hook.state_key.clone(),
        "trusted_hash": input.hook.trusted_hash.clone(),
        "trust_status": hook_trust_status(&input.hook.source, input.hook.trusted_hash.as_deref()),
    })
}

fn completed_hook_run_summary_json(
    event: HookEventName,
    run: &CompletedCommandHookRun,
    status: &str,
    duration_ms: Option<i64>,
    entries: Vec<Value>,
) -> Value {
    serde_json::json!({
        "id": run.hook_id.clone(),
        "event_name": event.as_str(),
        "handler_type": "command",
        "execution_mode": if run.async_run { "async" } else { "sync" },
        "scope": hook_scope_for_event(event),
        "source_path": run.source.path.clone(),
        "source": run.source.source.as_str(),
        "display_order": run.display_order,
        "status": status,
        "status_message": run.status_message.clone(),
        "started_at": run.started_at_ms,
        "completed_at": run.completed_at_ms,
        "duration_ms": duration_ms,
        "entries": entries,
        "command": run.command.clone(),
        "state_key": run.state_key.clone(),
        "trusted_hash": run.trusted_hash.clone(),
        "trust_status": hook_trust_status(&run.source, run.trusted_hash.as_deref()),
    })
}

fn hook_scope_for_event(event: HookEventName) -> &'static str {
    match event {
        HookEventName::SessionStart | HookEventName::SubagentStart => "thread",
        _ => "turn",
    }
}

fn hook_trust_status(source: &HookSourceMetadata, trusted_hash: Option<&str>) -> &'static str {
    if source.managed {
        "managed"
    } else if trusted_hash.is_some() {
        "trusted"
    } else {
        "untrusted"
    }
}

fn hook_run_status_for_outcome(status: i32, outcome: &HookRunOutcome) -> &'static str {
    if outcome.block_reason.is_some() {
        "blocked"
    } else if outcome.stop_reason.is_some() {
        "stopped"
    } else if status == 0 {
        "completed"
    } else {
        "failed"
    }
}

fn hook_output_entries(outcome: &HookRunOutcome, stderr: &str, status: i32) -> Vec<Value> {
    let mut entries = Vec::new();
    for context in &outcome.additional_contexts {
        entries.push(hook_output_entry("context", context));
    }
    for feedback in &outcome.feedback_messages {
        entries.push(hook_output_entry("feedback", feedback));
    }
    if let Some(reason) = outcome.block_reason.as_deref() {
        entries.push(hook_output_entry("stop", reason));
    }
    if let Some(reason) = outcome.stop_reason.as_deref() {
        entries.push(hook_output_entry("stop", reason));
    }
    if status != 0
        && outcome.block_reason.is_none()
        && outcome.stop_reason.is_none()
        && entries.is_empty()
    {
        let text = stderr
            .trim()
            .lines()
            .next()
            .filter(|line| !line.trim().is_empty())
            .unwrap_or("hook command failed");
        entries.push(hook_output_entry("error", text));
    }
    entries
}

fn hook_output_entry(kind: &str, text: &str) -> Value {
    serde_json::json!({
        "kind": kind,
        "text": truncate_text_for_event(text, 4000),
    })
}

fn write_hook_transcript_snapshot(
    store: &Store,
    session: &SessionMeta,
    event: HookEventName,
    hook_id: &str,
    configured_order: usize,
) -> Option<Result<PathBuf>> {
    let dir = store.state_dir().join("hook-transcripts").join(&session.id);
    let path = dir.join(format!(
        "{}-{}-{}.json",
        event.as_str(),
        configured_order,
        hook_id
    ));
    Some(write_session_transcript_snapshot(store, session, path))
}

fn write_session_transcript_snapshot(
    store: &Store,
    session: &SessionMeta,
    path: PathBuf,
) -> Result<PathBuf> {
    if let Some(dir) = path.parent() {
        std::fs::create_dir_all(dir)?;
    }
    let events = store.events_for_session(&session.id)?;
    let artifacts = store.artifacts_for_session(&session.id)?;
    let payload = serde_json::json!({
        "session": session,
        "events": events,
        "artifacts": artifacts,
    });
    std::fs::write(
        &path,
        format!("{}\n", serde_json::to_string_pretty(&payload)?),
    )?;
    Ok(path)
}

fn write_subagent_stop_transcript_snapshot(
    store: &Store,
    session: &SessionMeta,
    kind: &str,
) -> Result<PathBuf> {
    let dir = store.state_dir().join("hook-transcripts").join(&session.id);
    let path = dir.join(format!(
        "SubagentStop-{}-{}.json",
        kind,
        uuid::Uuid::new_v4()
    ));
    write_session_transcript_snapshot(store, session, path)
}

fn hook_group_matches(
    group: &HookMatcherGroup,
    call: Option<&ToolCall>,
    matcher_target: Option<&str>,
) -> bool {
    let matcher = group.matcher.as_deref().map(str::trim);
    if let Some(target) = matcher_target {
        return hook_matcher_matches(matcher, target);
    }
    let Some(call) = call else {
        return true;
    };
    hook_tool_name_candidates(call)
        .iter()
        .any(|candidate| hook_matcher_matches(matcher, candidate))
}

fn hook_tool_name_candidates(call: &ToolCall) -> Vec<String> {
    let canonical = hook_canonical_tool_name(call).to_string();
    let mut candidates = vec![canonical.clone()];
    if call.name != canonical {
        candidates.push(call.name.clone());
    }
    if let Some(namespace) = call.namespace.as_deref() {
        candidates.push(format!("{namespace}.{}", call.name));
    }
    for alias in hook_tool_matcher_aliases(call) {
        if !candidates.iter().any(|candidate| candidate == &alias) {
            candidates.push(alias);
        }
    }
    candidates
}

fn hook_tool_matcher_aliases(call: &ToolCall) -> Vec<String> {
    match call.name.as_str() {
        "apply_patch" => vec!["Write".to_string(), "Edit".to_string()],
        "spawn_agent" => vec!["Agent".to_string()],
        _ => Vec::new(),
    }
}

fn hook_matcher_matches(matcher: Option<&str>, candidate: &str) -> bool {
    let Some(matcher) = matcher.map(str::trim) else {
        return true;
    };
    if matcher.is_empty() || matcher == "*" {
        return true;
    }
    if hook_matcher_is_exact(matcher) {
        return matcher.split('|').any(|part| part == candidate);
    }
    regex::Regex::new(matcher)
        .map(|regex| regex.is_match(candidate))
        .unwrap_or(false)
}

fn hook_matcher_is_exact(matcher: &str) -> bool {
    matcher
        .chars()
        .all(|ch| ch.is_ascii_alphanumeric() || ch == '_' || ch == '|')
}

#[cfg(test)]
fn hook_command_input(
    store: &Store,
    session: &SessionMeta,
    event: HookEventName,
    call: Option<&ToolCall>,
    tool_input: Option<&Value>,
    model: &str,
    extra: Value,
) -> Value {
    hook_command_input_with_transcript(store, session, event, call, tool_input, model, extra, None)
}

#[allow(clippy::too_many_arguments)]
fn hook_command_input_with_transcript(
    store: &Store,
    session: &SessionMeta,
    event: HookEventName,
    call: Option<&ToolCall>,
    tool_input: Option<&Value>,
    model: &str,
    extra: Value,
    transcript_path: Option<&str>,
) -> Value {
    let events = store.events_for_session(&session.id).unwrap_or_default();
    let turn_id = active_request_user_input_turn_id(&events, &session.id);
    let (agent_id, agent_type) = if session.parent_id.is_some() {
        store
            .agent_summary_for_child(&session.id)
            .ok()
            .flatten()
            .map(|summary| {
                (
                    Value::String(session.id.clone()),
                    summary.agent_role.map(Value::String).unwrap_or(Value::Null),
                )
            })
            .unwrap_or_else(|| (Value::String(session.id.clone()), Value::Null))
    } else {
        (Value::Null, Value::Null)
    };
    let mut input = serde_json::json!({
        "session_id": session.id,
        "turn_id": turn_id,
        "agent_id": agent_id,
        "agent_type": agent_type,
        "transcript_path": transcript_path
            .map(|path| Value::String(path.to_string()))
            .unwrap_or(Value::Null),
        "cwd": session.cwd.as_str(),
        "hook_event_name": event.as_str(),
        "model": model,
        "permission_mode": "never",
    });
    if let Some(call) = call {
        input["tool_name"] = Value::String(hook_canonical_tool_name(call).to_string());
        input["matcher_aliases"] = Value::Array(
            hook_tool_matcher_aliases(call)
                .into_iter()
                .map(Value::String)
                .collect(),
        );
        input["tool_use_id"] = Value::String(call.id.clone());
        input["tool_input"] = tool_input
            .cloned()
            .unwrap_or_else(|| hook_visible_tool_input(call));
        input["raw_tool_input"] = call.arguments.clone();
    }
    if let (Value::Object(input), Value::Object(extra)) = (&mut input, extra) {
        input.extend(extra);
    }
    input
}

fn hook_visible_tool_input(call: &ToolCall) -> Value {
    match call.name.as_str() {
        "exec_command" => call
            .arguments
            .get("cmd")
            .and_then(Value::as_str)
            .map(|command| serde_json::json!({ "command": command }))
            .unwrap_or_else(|| call.arguments.clone()),
        "shell_command" => call
            .arguments
            .get("command")
            .and_then(Value::as_str)
            .map(|command| serde_json::json!({ "command": command }))
            .unwrap_or_else(|| call.arguments.clone()),
        "apply_patch" => apply_patch_hook_command(&call.arguments)
            .map(|command| serde_json::json!({ "command": command }))
            .unwrap_or_else(|| call.arguments.clone()),
        _ => call.arguments.clone(),
    }
}

fn hook_updated_input_to_tool_arguments(call: &ToolCall, updated_input: &Value) -> Value {
    match call.name.as_str() {
        "exec_command" => updated_input
            .get("command")
            .and_then(Value::as_str)
            .map(|command| {
                let mut arguments = call.arguments.as_object().cloned().unwrap_or_default();
                arguments.insert("cmd".to_string(), Value::String(command.to_string()));
                arguments.remove("command");
                Value::Object(arguments)
            })
            .unwrap_or_else(|| updated_input.clone()),
        "shell_command" => updated_input
            .get("cmd")
            .and_then(Value::as_str)
            .map(|command| {
                let mut arguments = call.arguments.as_object().cloned().unwrap_or_default();
                arguments.insert("command".to_string(), Value::String(command.to_string()));
                arguments.remove("cmd");
                Value::Object(arguments)
            })
            .unwrap_or_else(|| updated_input.clone()),
        "apply_patch" => updated_input
            .get("command")
            .and_then(Value::as_str)
            .map(|patch| Value::String(patch.to_string()))
            .unwrap_or_else(|| updated_input.clone()),
        _ => updated_input.clone(),
    }
}

fn apply_patch_hook_command(arguments: &Value) -> Option<&str> {
    arguments
        .as_str()
        .or_else(|| arguments.get("patch").and_then(Value::as_str))
}

fn hook_canonical_tool_name(call: &ToolCall) -> &str {
    match call.name.as_str() {
        "exec_command" | "shell_command" => "Bash",
        "apply_patch" => "apply_patch",
        "read_file" => "Read",
        "search_files" => "Grep",
        "list_files" => "Glob",
        "view_image" => "ViewImage",
        "spawn_agent" => "spawn_agent",
        "done" => "Done",
        other => other,
    }
}

struct HookProcessOutput {
    status: i32,
    stdout: String,
    stderr: String,
}

fn run_hook_command_process(
    cwd: &str,
    command: &str,
    input: &Value,
    timeout: Option<Duration>,
) -> Result<HookProcessOutput> {
    let mut child = if cfg!(windows) {
        ProcessCommand::new("cmd")
            .args(["/C", command])
            .current_dir(cwd)
            .stdin(Stdio::piped())
            .stdout(Stdio::piped())
            .stderr(Stdio::piped())
            .spawn()
    } else {
        ProcessCommand::new("sh")
            .args(["-lc", command])
            .current_dir(cwd)
            .stdin(Stdio::piped())
            .stdout(Stdio::piped())
            .stderr(Stdio::piped())
            .spawn()
    }
    .with_context(|| format!("spawn hook command `{command}`"))?;
    if let Some(stdin) = child.stdin.as_mut() {
        let input = serde_json::to_vec(input)?;
        stdin.write_all(&input)?;
    }
    drop(child.stdin.take());
    let started = Instant::now();
    if let Some(timeout) = timeout {
        loop {
            if child.try_wait()?.is_some() {
                break;
            }
            if started.elapsed() >= timeout {
                let _ = child.kill();
                let output = child.wait_with_output()?;
                return Ok(HookProcessOutput {
                    status: -1,
                    stdout: String::from_utf8_lossy(&output.stdout).to_string(),
                    stderr: format!(
                        "{}\nhook command timed out after {} ms",
                        String::from_utf8_lossy(&output.stderr),
                        timeout.as_millis()
                    )
                    .trim()
                    .to_string(),
                });
            }
            thread::sleep(Duration::from_millis(20));
        }
    }
    let output = child.wait_with_output()?;
    Ok(HookProcessOutput {
        status: output.status.code().unwrap_or(-1),
        stdout: String::from_utf8_lossy(&output.stdout).to_string(),
        stderr: String::from_utf8_lossy(&output.stderr).to_string(),
    })
}

fn parse_hook_command_output(
    event: HookEventName,
    stdout: &str,
    stderr: &str,
    status: i32,
) -> HookRunOutcome {
    let mut outcome = HookRunOutcome::default();
    let trimmed = stdout.trim();
    if !trimmed.is_empty() {
        if let Ok(value) = serde_json::from_str::<Value>(trimmed) {
            apply_json_hook_output(event, &mut outcome, &value);
        } else if status == 0 {
            outcome.additional_contexts.push(trimmed.to_string());
        }
    }
    if status == 2 && outcome.block_reason.is_none() && outcome.stop_reason.is_none() {
        if let Some(reason) = stderr
            .trim()
            .lines()
            .find(|line| !line.trim().is_empty())
            .map(str::to_string)
        {
            match event {
                HookEventName::PreToolUse => outcome.block_reason = Some(reason),
                HookEventName::UserPromptSubmit | HookEventName::Stop => {
                    outcome.stop_reason = Some(reason)
                }
                HookEventName::PostToolUse | HookEventName::SubagentStop => {
                    outcome.feedback_messages.push(reason)
                }
                HookEventName::PreCompact => outcome.stop_reason = Some(reason),
                _ => outcome.additional_contexts.push(reason),
            }
        } else {
            outcome.additional_contexts.push(format!(
                "{} hook exited with code 2 without required stderr feedback",
                event.as_str()
            ));
        }
    } else if status != 0 && outcome.block_reason.is_none() && outcome.stop_reason.is_none() {
        let reason = stderr
            .trim()
            .lines()
            .next()
            .filter(|line| !line.trim().is_empty())
            .unwrap_or("hook command failed")
            .to_string();
        outcome.additional_contexts.push(format!(
            "{} hook command exited with status {status}: {reason}",
            event.as_str()
        ));
    }
    outcome
}

fn apply_json_hook_output(event: HookEventName, outcome: &mut HookRunOutcome, value: &Value) {
    if value
        .get("continue")
        .and_then(Value::as_bool)
        .is_some_and(|continue_run| !continue_run)
    {
        outcome.stop_reason = Some(
            value
                .get("stopReason")
                .or_else(|| value.get("reason"))
                .and_then(Value::as_str)
                .unwrap_or("hook requested stop")
                .to_string(),
        );
    }
    if let Some(system_message) = value.get("systemMessage").and_then(Value::as_str) {
        if !system_message.trim().is_empty() {
            outcome.additional_contexts.push(system_message.to_string());
        }
    }
    if value.get("decision").and_then(Value::as_str) == Some("block") {
        let reason = value
            .get("reason")
            .and_then(Value::as_str)
            .unwrap_or("hook blocked the action")
            .to_string();
        if event == HookEventName::PostToolUse {
            outcome.feedback_messages.push(reason);
        } else {
            outcome.block_reason = Some(reason);
        }
    } else if event == HookEventName::PostToolUse {
        if let Some(reason) = value.get("reason").and_then(Value::as_str) {
            if !reason.trim().is_empty() {
                outcome.feedback_messages.push(reason.to_string());
            }
        }
    }
    let hook_specific = value
        .get("hookSpecificOutput")
        .or_else(|| value.get("hook_specific_output"));
    if let Some(hook_specific) = hook_specific {
        if let Some(additional_context) = hook_specific
            .get("additionalContext")
            .or_else(|| hook_specific.get("additional_context"))
            .and_then(Value::as_str)
        {
            if !additional_context.trim().is_empty() {
                outcome
                    .additional_contexts
                    .push(additional_context.to_string());
            }
        }
        if event == HookEventName::PreToolUse {
            if let Some(updated_input) = hook_specific
                .get("updatedInput")
                .or_else(|| hook_specific.get("updated_input"))
            {
                outcome.updated_input = Some(updated_input.clone());
            }
        }
    }
}

#[derive(Clone, Debug, Default, PartialEq, Eq)]
struct WorktreeSnapshot {
    status: String,
    diff: String,
    changed_files: Vec<String>,
}

fn git_worktree_snapshot(cwd: &str) -> Option<WorktreeSnapshot> {
    let inside = run_git_for_snapshot(cwd, &["rev-parse", "--is-inside-work-tree"])?;
    if inside.trim() != "true" {
        return None;
    }
    let status = run_git_for_snapshot(cwd, &["status", "--short"])?;
    let unstaged_diff = run_git_for_snapshot(cwd, &["diff", "--no-ext-diff", "--no-color", "--"])?;
    let staged_diff = run_git_for_snapshot(
        cwd,
        &["diff", "--cached", "--no-ext-diff", "--no-color", "--"],
    )?;
    let diff = combine_git_diff_sections(&staged_diff, &unstaged_diff);
    let unstaged_names = run_git_for_snapshot(cwd, &["diff", "--name-only", "--"])?;
    let staged_names = run_git_for_snapshot(cwd, &["diff", "--cached", "--name-only", "--"])?;
    let mut seen = HashSet::new();
    let mut changed_files = Vec::new();
    for name in staged_names
        .lines()
        .chain(unstaged_names.lines())
        .chain(status.lines().filter_map(status_changed_path))
    {
        let name = name.trim();
        if !name.is_empty() && seen.insert(name.to_string()) {
            changed_files.push(name.to_string());
        }
    }
    Some(WorktreeSnapshot {
        status,
        diff,
        changed_files,
    })
}

fn run_git_for_snapshot(cwd: &str, args: &[&str]) -> Option<String> {
    let output = ProcessCommand::new("git")
        .arg("-C")
        .arg(cwd)
        .args(args)
        .output()
        .ok()?;
    output
        .status
        .success()
        .then(|| String::from_utf8_lossy(&output.stdout).to_string())
}

fn turn_diff_display_root(cwd: &str) -> PathBuf {
    git_worktree_root(cwd).unwrap_or_else(|| PathBuf::from(cwd))
}

fn git_worktree_root(cwd: &str) -> Option<PathBuf> {
    run_git_for_snapshot(cwd, &["rev-parse", "--show-toplevel"])
        .map(|root| root.trim().to_string())
        .filter(|root| !root.is_empty())
        .map(PathBuf::from)
}

fn combine_git_diff_sections(staged_diff: &str, unstaged_diff: &str) -> String {
    match (
        staged_diff.trim().is_empty(),
        unstaged_diff.trim().is_empty(),
    ) {
        (true, true) => String::new(),
        (false, true) => staged_diff.to_string(),
        (true, false) => unstaged_diff.to_string(),
        (false, false) => {
            let mut combined = staged_diff.to_string();
            if !combined.ends_with('\n') {
                combined.push('\n');
            }
            combined.push_str(unstaged_diff);
            combined
        }
    }
}

fn status_changed_path(line: &str) -> Option<&str> {
    let text = line.get(3..)?.trim();
    if text.is_empty() {
        return None;
    }
    text.split(" -> ").last()
}

fn append_turn_git_diff_if_changed(
    store: &Store,
    session: &SessionMeta,
    before: Option<&WorktreeSnapshot>,
    start_seq: i64,
    turn_idx: usize,
) -> Result<()> {
    let Some(before) = before else {
        return Ok(());
    };
    let Some(after) = git_worktree_snapshot(&session.cwd) else {
        return Ok(());
    };
    if &after == before {
        return Ok(());
    }
    if exact_patch_turn_diff_emitted_after(store, &session.id, start_seq)? {
        return Ok(());
    }
    let preexisting_dirty = !before.status.trim().is_empty() || !before.diff.trim().is_empty();
    let diff_truncated = !preexisting_dirty && after.diff.chars().count() > 60_000;
    let mut payload = serde_json::json!({
        "source": "git_worktree",
        "turn_idx": turn_idx,
        "exact": !preexisting_dirty,
        "preexisting_dirty_worktree": preexisting_dirty,
        "changed_files": after.changed_files.len(),
        "files": after.changed_files,
        "status": after.status,
        "before_status": before.status,
        "diff_truncated": diff_truncated,
    });
    if preexisting_dirty {
        payload["unified_diff"] = Value::Null;
        payload["reason"] =
            Value::String("worktree had preexisting changes before this tool batch".to_string());
    } else {
        payload["unified_diff"] = Value::String(truncate_text_for_event(&after.diff, 60_000));
    }
    store.append_event(&session.id, "turn.diff", payload)?;
    Ok(())
}

fn exact_patch_turn_diff_emitted_after(
    store: &Store,
    session_id: &str,
    start_seq: i64,
) -> Result<bool> {
    Ok(store.events_for_session(session_id)?.iter().any(|event| {
        event.seq > start_seq
            && event.event_type == "turn.diff"
            && event.payload.get("source").and_then(Value::as_str) == Some("apply_patch")
            && event
                .payload
                .get("exact")
                .and_then(Value::as_bool)
                .unwrap_or(false)
            && event
                .payload
                .get("cumulative")
                .and_then(Value::as_bool)
                .unwrap_or(false)
    }))
}

fn provider_messages_from_events(events: &[browser_use_protocol::EventRecord]) -> Vec<Value> {
    let (replay_start_seq, mut messages, initial_context_already_in_history) =
        latest_compaction_replacement_history(events)
            .map(|state| {
                (
                    state.seq,
                    state.messages,
                    state.initial_context_already_in_history,
                )
            })
            .unwrap_or_else(|| (0, Vec::new(), false));
    let replay_events = rollback_filtered_events_after(events, replay_start_seq, &mut messages);
    provider_messages_from_event_slice(
        &replay_events,
        &mut messages,
        initial_context_already_in_history,
        false,
    )
}

fn provider_messages_from_events_for_fork(
    events: &[browser_use_protocol::EventRecord],
) -> Vec<Value> {
    let (replay_start_seq, mut messages, initial_context_already_in_history) =
        latest_compaction_replacement_history(events)
            .map(|state| {
                (
                    state.seq,
                    state.messages,
                    state.initial_context_already_in_history,
                )
            })
            .unwrap_or_else(|| (0, Vec::new(), false));
    let replay_events =
        rollback_filtered_events_after_for_fork(events, replay_start_seq, &mut messages);
    provider_messages_from_event_slice(
        &replay_events,
        &mut messages,
        initial_context_already_in_history,
        true,
    )
}

struct CompactionCheckpoint {
    seq: i64,
    messages: Vec<Value>,
    response_items: Option<Vec<Value>>,
    context_baseline: Option<PreviousTurnSettings>,
    has_replacement_history: bool,
}

struct CompactionReplayState {
    seq: i64,
    messages: Vec<Value>,
    initial_context_already_in_history: bool,
}

fn latest_compaction_replacement_history(events: &[EventRecord]) -> Option<CompactionReplayState> {
    latest_compaction_checkpoint(events).map(|checkpoint| {
        let messages = match checkpoint.response_items {
            Some(response_items) => response_items_to_provider_messages(&response_items),
            None => checkpoint.messages,
        };
        let mut initial_context_already_in_history = checkpoint.has_replacement_history;
        let mut messages = messages;
        if !initial_context_already_in_history {
            let mut initial_context =
                initial_context_messages_from_events(events, None, true, true);
            if !initial_context.is_empty() {
                initial_context.append(&mut messages);
                messages = initial_context;
                initial_context_already_in_history = true;
            }
        }
        CompactionReplayState {
            seq: checkpoint.seq,
            messages,
            initial_context_already_in_history,
        }
    })
}

fn latest_compaction_checkpoint(events: &[EventRecord]) -> Option<CompactionCheckpoint> {
    events.iter().rev().find_map(|event| {
        if event.event_type != "session.compacted" {
            return None;
        }
        let messages = event
            .payload
            .get("replacement_messages")
            .and_then(Value::as_array)
            .cloned()
            .unwrap_or_default();
        let response_items = event
            .payload
            .get("replacement_response_items")
            .and_then(Value::as_array)
            .cloned();
        let context_baseline = event
            .payload
            .get("context_baseline")
            .and_then(previous_turn_settings_from_baseline_payload);
        Some(CompactionCheckpoint {
            seq: event.seq,
            messages,
            response_items,
            context_baseline,
            has_replacement_history: event.payload.get("replacement_messages").is_some()
                || event.payload.get("replacement_response_items").is_some(),
        })
    })
}

pub fn rollback_filtered_event_records(events: &[EventRecord]) -> Vec<&EventRecord> {
    rollback_filtered_events(events)
}

fn rollback_filtered_events(events: &[EventRecord]) -> Vec<&EventRecord> {
    let mut messages = Vec::new();
    rollback_filtered_events_after(events, 0, &mut messages)
}

fn rollback_filtered_events_after<'a>(
    events: &'a [EventRecord],
    after_seq: i64,
    messages: &mut Vec<Value>,
) -> Vec<&'a EventRecord> {
    rollback_filtered_events_after_with_options(events, after_seq, messages, true)
}

fn rollback_filtered_events_after_for_fork<'a>(
    events: &'a [EventRecord],
    after_seq: i64,
    messages: &mut Vec<Value>,
) -> Vec<&'a EventRecord> {
    rollback_filtered_events_after_with_options(events, after_seq, messages, true)
}

fn rollback_filtered_events_after_with_options<'a>(
    events: &'a [EventRecord],
    after_seq: i64,
    messages: &mut Vec<Value>,
    count_inter_agent_turns: bool,
) -> Vec<&'a EventRecord> {
    let mut replay_events = Vec::new();
    for event in events.iter().filter(|event| event.seq > after_seq) {
        if event.event_type == SESSION_ROLLBACK_EVENT {
            rollback_last_n_user_turns(
                &mut replay_events,
                messages,
                rollback_turn_count(&event.payload),
                count_inter_agent_turns,
            );
        } else {
            replay_events.push(event);
        }
    }
    replay_events
}

fn rollback_turn_count(payload: &Value) -> usize {
    match payload
        .get("num_turns")
        .or_else(|| payload.get("turns"))
        .or_else(|| payload.get("n"))
        .and_then(Value::as_u64)
    {
        Some(count) => usize::try_from(count).unwrap_or(usize::MAX),
        None => 1,
    }
}

fn rollback_last_n_user_turns(
    events: &mut Vec<&EventRecord>,
    checkpoint_messages: &mut Vec<Value>,
    mut count: usize,
    count_inter_agent_turns: bool,
) {
    while count > 0 {
        if rollback_last_user_event_turn(events, count_inter_agent_turns)
            || rollback_last_user_message_turn(checkpoint_messages, count_inter_agent_turns)
        {
            count -= 1;
        } else {
            break;
        }
    }
}

fn rollback_last_user_event_turn(
    events: &mut Vec<&EventRecord>,
    count_inter_agent_turns: bool,
) -> bool {
    let Some(user_pos) = events
        .iter()
        .rposition(|event| is_real_user_event_for_rollback(event, count_inter_agent_turns))
    else {
        return false;
    };
    let target_seq = events[user_pos].seq;
    let mut truncate_at = user_pos;
    while truncate_at > 0 && contextual_event_targets_turn(events[truncate_at - 1], target_seq) {
        truncate_at -= 1;
    }
    events.truncate(truncate_at);
    true
}

fn is_real_user_event_for_rollback(event: &EventRecord, count_inter_agent_turns: bool) -> bool {
    is_real_user_event(event)
        || (count_inter_agent_turns && agent_message_is_inter_agent_turn_event(event))
}

fn is_real_user_event(event: &EventRecord) -> bool {
    matches!(
        event.event_type.as_str(),
        "session.input" | "session.followup"
    )
}

fn agent_message_is_inter_agent_turn_event(event: &EventRecord) -> bool {
    matches!(
        event.event_type.as_str(),
        "agent.message" | "agent.mailbox_input"
    ) && event
        .payload
        .get("content")
        .and_then(Value::as_str)
        .is_some()
}

fn contextual_event_targets_turn(event: &EventRecord, target_seq: i64) -> bool {
    matches!(
        event.event_type.as_str(),
        "workspace.context"
            | MODEL_SWITCH_CONTEXT_EVENT
            | PERSONALITY_CONTEXT_EVENT
            | COLLABORATION_CONTEXT_EVENT
            | GENERATED_IMAGE_CONTEXT_EVENT
    ) && event.payload.get("before_seq").and_then(Value::as_i64) == Some(target_seq)
}

fn rollback_last_user_message_turn(
    messages: &mut Vec<Value>,
    count_inter_agent_turns: bool,
) -> bool {
    let Some(user_pos) = messages
        .iter()
        .rposition(|message| is_user_message_for_rollback(message, count_inter_agent_turns))
    else {
        return false;
    };
    let has_prior_real_user = messages[..user_pos]
        .iter()
        .any(|message| is_user_message_for_rollback(message, count_inter_agent_turns));
    let mut truncate_at = user_pos;
    if has_prior_real_user {
        while truncate_at > 0 && is_contextual_provider_message(&messages[truncate_at - 1]) {
            truncate_at -= 1;
        }
    }
    messages.truncate(truncate_at);
    true
}

fn is_user_message_for_rollback(message: &Value, count_inter_agent_turns: bool) -> bool {
    is_real_user_message(message)
        || (count_inter_agent_turns && provider_message_is_inter_agent_instruction(message))
}

fn is_real_user_message(message: &Value) -> bool {
    message.get("role").and_then(Value::as_str) == Some("user")
        && message.get("name").is_none()
        && !is_turn_aborted_message(message)
        && !is_skill_context_message(message)
        && !is_subagent_notification_context_message(message)
}

fn is_contextual_provider_message(message: &Value) -> bool {
    if is_turn_aborted_message(message) {
        return true;
    }
    matches!(
        message.get("name").and_then(Value::as_str),
        Some(WORKSPACE_CONTEXT_MESSAGE_NAME)
            | Some(PERMISSIONS_CONTEXT_MESSAGE_NAME)
            | Some(MODEL_SWITCH_CONTEXT_MESSAGE_NAME)
            | Some(PERSONALITY_CONTEXT_MESSAGE_NAME)
            | Some(COLLABORATION_CONTEXT_MESSAGE_NAME)
            | Some(MENTION_CONTEXT_MESSAGE_NAME)
            | Some(GENERATED_IMAGE_CONTEXT_MESSAGE_NAME)
    )
}

fn provider_history_has_open_turn(messages: &[Value]) -> bool {
    let Some(user_pos) = messages
        .iter()
        .rposition(|message| is_user_message_for_rollback(message, true))
    else {
        return false;
    };
    !messages[user_pos + 1..].iter().any(is_turn_aborted_message)
}

fn inter_agent_provider_message_from_event(event: &EventRecord) -> Option<Value> {
    let content = event.payload.get("content").and_then(Value::as_str)?;
    if is_v1_subagent_notification_event(event, content) {
        return Some(serde_json::json!({
            "role": "user",
            "content": content,
        }));
    }
    let author = event
        .payload
        .get("author_path")
        .and_then(Value::as_str)
        .unwrap_or("/root");
    let recipient = event
        .payload
        .get("recipient_path")
        .and_then(Value::as_str)
        .or_else(|| event.payload.get("agent_path").and_then(Value::as_str))
        .unwrap_or("/root");
    let trigger_turn = event
        .payload
        .get("trigger_turn")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    Some(serde_json::json!({
        "role": "assistant",
        "phase": "commentary",
        "content": serde_json::to_string(&serde_json::json!({
            "author": author,
            "recipient": recipient,
            "other_recipients": [],
            "content": content,
            "trigger_turn": trigger_turn,
        })).ok()?,
    }))
}

fn provider_messages_from_event_slice(
    events: &[&browser_use_protocol::EventRecord],
    messages: &mut Vec<Value>,
    has_compaction_checkpoint: bool,
    include_agent_messages: bool,
) -> Vec<Value> {
    let mut assistant_text = String::new();
    let mut assistant_phase = None::<String>;
    let mut assistant_reasoning_content = String::new();
    let mut assistant_tool_calls = Vec::<Value>::new();
    let mut tool_names = HashMap::<String, String>::new();
    let mut emitted_tool_messages = HashSet::<String>::new();
    let mut turn_open = has_compaction_checkpoint && provider_history_has_open_turn(messages);
    let mut suppress_terminal_tail = false;
    let first_user_message_seq = first_user_message_seq_from_iter(events.iter().copied());
    let mut initial_context_messages = if has_compaction_checkpoint {
        Vec::new()
    } else {
        initial_context_messages_from_iter(
            events.iter().copied(),
            first_user_message_seq,
            false,
            false,
        )
    };
    let mut emitted_initial_context_messages = has_compaction_checkpoint;
    let mut workspace_contexts_by_before_seq = events
        .iter()
        .filter(|event| event.event_type == "workspace.context")
        .filter_map(|event| {
            let before_seq = event.payload.get("before_seq").and_then(Value::as_i64)?;
            if !has_compaction_checkpoint && Some(before_seq) == first_user_message_seq {
                return None;
            }
            workspace_context_message_from_payload(&event.payload)
                .map(|message| (before_seq, message))
        })
        .fold(
            HashMap::<i64, Vec<Value>>::new(),
            |mut acc, (seq, message)| {
                acc.entry(seq).or_default().push(message);
                acc
            },
        );
    let mut developer_contexts_by_before_seq = events
        .iter()
        .filter(|event| {
            matches!(
                event.event_type.as_str(),
                MODEL_SWITCH_CONTEXT_EVENT
                    | PERSONALITY_CONTEXT_EVENT
                    | COLLABORATION_CONTEXT_EVENT
                    | GENERATED_IMAGE_CONTEXT_EVENT
            )
        })
        .filter_map(|event| {
            let before_seq = event.payload.get("before_seq").and_then(Value::as_i64)?;
            let content = event.payload.get("content").and_then(Value::as_str)?;
            Some((
                before_seq,
                developer_context_message_for_event(&event.event_type, content.to_string()),
            ))
        })
        .fold(
            HashMap::<i64, Vec<Value>>::new(),
            |mut acc, (seq, message)| {
                acc.entry(seq).or_default().push(message);
                acc
            },
        );

    fn flush_assistant(
        messages: &mut Vec<Value>,
        assistant_text: &mut String,
        assistant_phase: &mut Option<String>,
        assistant_reasoning_content: &mut String,
        assistant_tool_calls: &mut Vec<Value>,
    ) {
        if assistant_text.is_empty() && assistant_tool_calls.is_empty() {
            assistant_reasoning_content.clear();
            return;
        }
        let mut message = serde_json::json!({
            "role": "assistant",
            "content": std::mem::take(assistant_text),
            "tool_calls": std::mem::take(assistant_tool_calls),
        });
        if let Some(phase) = assistant_phase.take() {
            message["phase"] = Value::String(phase);
        }
        if message
            .get("tool_calls")
            .and_then(Value::as_array)
            .is_some_and(|calls| !calls.is_empty())
            && !assistant_reasoning_content.is_empty()
        {
            message["reasoning_content"] =
                serde_json::json!(std::mem::take(assistant_reasoning_content));
        } else {
            assistant_reasoning_content.clear();
        }
        messages.push(message);
    }

    fn merge_response_item_assistant_text(
        messages: &mut Vec<Value>,
        assistant_text: &mut String,
        assistant_phase: &mut Option<String>,
        assistant_reasoning_content: &mut String,
        assistant_tool_calls: &mut Vec<Value>,
        text: &str,
        phase: Option<&str>,
    ) {
        if text.is_empty() {
            return;
        }
        if assistant_text == text || assistant_text.trim() == text.trim() {
            assistant_text.clear();
            assistant_text.push_str(text);
            *assistant_phase = phase.map(ToOwned::to_owned);
            return;
        }
        if !assistant_text.is_empty()
            && assistant_text.ends_with(text)
            && assistant_text.len() > text.len()
        {
            let prefix_len = assistant_text.len() - text.len();
            let prefix = assistant_text[..prefix_len].to_string();
            assistant_text.clear();
            assistant_text.push_str(&prefix);
            flush_assistant(
                messages,
                assistant_text,
                assistant_phase,
                assistant_reasoning_content,
                assistant_tool_calls,
            );
            assistant_text.push_str(text);
            *assistant_phase = phase.map(ToOwned::to_owned);
            return;
        }
        if !assistant_text.is_empty() || !assistant_tool_calls.is_empty() {
            flush_assistant(
                messages,
                assistant_text,
                assistant_phase,
                assistant_reasoning_content,
                assistant_tool_calls,
            );
        }
        assistant_text.push_str(text);
        *assistant_phase = phase.map(ToOwned::to_owned);
    }

    for event in events {
        match event.event_type.as_str() {
            "agent.context" => {
                flush_assistant(
                    messages,
                    &mut assistant_text,
                    &mut assistant_phase,
                    &mut assistant_reasoning_content,
                    &mut assistant_tool_calls,
                );
                if let Some(fork_response_items) = event
                    .payload
                    .get("fork_response_items")
                    .and_then(Value::as_array)
                {
                    messages.extend(response_items_to_provider_messages(fork_response_items));
                }
                let mut sections = Vec::new();
                if let Some(role) = event.payload.get("role").and_then(Value::as_str) {
                    let canonical_task_sentence = event
                        .payload
                        .get("agent_path")
                        .and_then(Value::as_str)
                        .map(|path| {
                            format!(
                                " Canonical task name: {path}. This is an agent routing name, not a filesystem path."
                            )
                        })
                        .unwrap_or_default();
                    let explorer_instruction = if role.to_ascii_lowercase().contains("explor") {
                        "As the explorer, inspect the repository/codebase directly with local tools from the task cwd. This explorer role only applies after spawning was otherwise authorized. Use `.` for the repository root; do not use your canonical task name as a directory. Do not spawn another explorer for this same repository-analysis task unless explicitly instructed."
                    } else {
                        ""
                    };
                    sections.push(render_prompt_template(
                        include_str!("../../../prompts/helper-session-identity.md"),
                        &[
                            ("{{role}}", role),
                            ("{{canonical_task_sentence}}", &canonical_task_sentence),
                            ("{{explorer_instruction}}", explorer_instruction),
                        ],
                    ));
                }
                let has_fork_history = event.payload.get("history_mode").and_then(Value::as_str)
                    == Some("fork_response_items");
                if !has_fork_history {
                    if let Some(context) = event.payload.get("context") {
                        let context = context.to_string();
                        sections.push(render_prompt_template(
                            include_str!("../../../prompts/helper-session-inherited-context.md"),
                            &[("{{context}}", &context)],
                        ));
                    }
                }
                if !sections.is_empty() {
                    messages.push(serde_json::json!({
                        "role": "system",
                        "content": sections.join("\n\n"),
                    }));
                }
            }
            "agent.message" => {
                if include_agent_messages {
                    flush_assistant(
                        messages,
                        &mut assistant_text,
                        &mut assistant_phase,
                        &mut assistant_reasoning_content,
                        &mut assistant_tool_calls,
                    );
                    if let Some(message) = inter_agent_provider_message_from_event(event) {
                        messages.push(message);
                    }
                }
            }
            "agent.mailbox_input" => {
                flush_assistant(
                    messages,
                    &mut assistant_text,
                    &mut assistant_phase,
                    &mut assistant_reasoning_content,
                    &mut assistant_tool_calls,
                );
                if let Some(message) = inter_agent_provider_message_from_event(event) {
                    messages.push(message);
                }
            }
            "workspace.context" => {
                continue;
            }
            GENERATED_IMAGE_CONTEXT_EVENT => {
                if event
                    .payload
                    .get("before_seq")
                    .and_then(Value::as_i64)
                    .is_some()
                {
                    continue;
                }
                flush_assistant(
                    messages,
                    &mut assistant_text,
                    &mut assistant_phase,
                    &mut assistant_reasoning_content,
                    &mut assistant_tool_calls,
                );
                if let Some(content) = event.payload.get("content").and_then(Value::as_str) {
                    messages.push(generated_image_context_message(content.to_string()));
                    turn_open = true;
                }
            }
            "session.input" | "session.followup" => {
                suppress_terminal_tail = false;
                if !emitted_initial_context_messages {
                    flush_assistant(
                        messages,
                        &mut assistant_text,
                        &mut assistant_phase,
                        &mut assistant_reasoning_content,
                        &mut assistant_tool_calls,
                    );
                    messages.append(&mut initial_context_messages);
                    emitted_initial_context_messages = true;
                }
                if let Some(contexts) = developer_contexts_by_before_seq.remove(&event.seq) {
                    flush_assistant(
                        messages,
                        &mut assistant_text,
                        &mut assistant_phase,
                        &mut assistant_reasoning_content,
                        &mut assistant_tool_calls,
                    );
                    for message in contexts {
                        messages.push(message);
                    }
                }
                if let Some(contexts) = workspace_contexts_by_before_seq.remove(&event.seq) {
                    flush_assistant(
                        messages,
                        &mut assistant_text,
                        &mut assistant_phase,
                        &mut assistant_reasoning_content,
                        &mut assistant_tool_calls,
                    );
                    for message in contexts {
                        messages.push(message);
                    }
                }
                flush_assistant(
                    messages,
                    &mut assistant_text,
                    &mut assistant_phase,
                    &mut assistant_reasoning_content,
                    &mut assistant_tool_calls,
                );
                messages.extend(session_event_user_messages(&event.payload));
                turn_open = true;
            }
            MODEL_SWITCH_CONTEXT_EVENT
            | PERSONALITY_CONTEXT_EVENT
            | COLLABORATION_CONTEXT_EVENT => {
                if event
                    .payload
                    .get("before_seq")
                    .and_then(Value::as_i64)
                    .is_some()
                {
                    continue;
                }
                flush_assistant(
                    messages,
                    &mut assistant_text,
                    &mut assistant_phase,
                    &mut assistant_reasoning_content,
                    &mut assistant_tool_calls,
                );
                if let Some(content) = event.payload.get("content").and_then(Value::as_str) {
                    messages.push(developer_context_message_for_event(
                        &event.event_type,
                        content.to_string(),
                    ));
                }
            }
            "model.response.output_item" => {
                if suppress_terminal_tail {
                    continue;
                }
                let Some(item) = event.payload.get("item") else {
                    continue;
                };
                match item.get("type").and_then(Value::as_str) {
                    Some("message") => {
                        if item.get("role").and_then(Value::as_str) == Some("assistant") {
                            if let Some(text) = response_message_item_text(item) {
                                merge_response_item_assistant_text(
                                    messages,
                                    &mut assistant_text,
                                    &mut assistant_phase,
                                    &mut assistant_reasoning_content,
                                    &mut assistant_tool_calls,
                                    &text,
                                    item.get("phase").and_then(Value::as_str),
                                );
                                turn_open = true;
                            }
                        }
                    }
                    Some("function_call") | Some("custom_tool_call") => {
                        if let Some(call) = response_output_item_tool_call_value(item) {
                            if let Some(call_id) = tool_call_id_from_value(&call) {
                                if assistant_tool_calls.iter().any(|existing| {
                                    tool_call_id_from_value(existing) == Some(call_id)
                                }) {
                                    continue;
                                }
                                if let Some(name) = call.get("name").and_then(Value::as_str) {
                                    tool_names.insert(call_id.to_string(), name.to_string());
                                }
                            }
                            assistant_tool_calls.push(call);
                            turn_open = true;
                        }
                    }
                    Some(_) if is_raw_response_item_provider_message(item) => {
                        flush_assistant(
                            messages,
                            &mut assistant_text,
                            &mut assistant_phase,
                            &mut assistant_reasoning_content,
                            &mut assistant_tool_calls,
                        );
                        messages.push(item.clone());
                        turn_open = true;
                    }
                    _ => {}
                }
            }
            MODEL_RESPONSE_INPUT_ITEM_EVENT => {
                if suppress_terminal_tail {
                    continue;
                }
                let Some(item) = event.payload.get("item") else {
                    continue;
                };
                let Some(call_id) = response_input_item_call_id(item) else {
                    continue;
                };
                flush_assistant(
                    messages,
                    &mut assistant_text,
                    &mut assistant_phase,
                    &mut assistant_reasoning_content,
                    &mut assistant_tool_calls,
                );
                let message = response_input_item_tool_message(item, &event.payload, &tool_names);
                if let Some(pos) = messages.iter().rposition(|message| {
                    message.get("role").and_then(Value::as_str) == Some("tool")
                        && message.get("tool_call_id").and_then(Value::as_str) == Some(call_id)
                }) {
                    messages[pos] = message;
                } else {
                    messages.push(message);
                }
                emitted_tool_messages.insert(call_id.to_string());
                turn_open = true;
            }
            "model.delta" => {
                if suppress_terminal_tail {
                    continue;
                }
                if let Some(text) = event.payload.get("text").and_then(Value::as_str) {
                    if let Some(delta) = assistant_delta_to_append(&assistant_text, text) {
                        assistant_text.push_str(&delta);
                        turn_open = true;
                    }
                }
            }
            "model.thinking_delta" => {
                if let Some(text) = event.payload.get("text").and_then(Value::as_str) {
                    assistant_reasoning_content.push_str(text);
                }
            }
            "model.tool_call" => {
                if suppress_terminal_tail {
                    continue;
                }
                let call = event.payload.clone();
                if let Some(call_id) = call.get("id").and_then(Value::as_str) {
                    if assistant_tool_calls
                        .iter()
                        .any(|existing| tool_call_id_from_value(existing) == Some(call_id))
                    {
                        continue;
                    }
                    if let Some(name) = call.get("name").and_then(Value::as_str) {
                        tool_names.insert(call_id.to_string(), name.to_string());
                    }
                }
                assistant_tool_calls.push(call);
                turn_open = true;
            }
            "tool.output" => {
                if suppress_terminal_tail {
                    continue;
                }
                flush_assistant(
                    messages,
                    &mut assistant_text,
                    &mut assistant_phase,
                    &mut assistant_reasoning_content,
                    &mut assistant_tool_calls,
                );
                if let Some(call_id) = event.payload.get("tool_call_id").and_then(Value::as_str) {
                    messages.push(tool_message_from_output_event(&event.payload, call_id));
                    emitted_tool_messages.insert(call_id.to_string());
                    turn_open = true;
                }
            }
            "tool.failed" => {
                if suppress_terminal_tail {
                    continue;
                }
                flush_assistant(
                    messages,
                    &mut assistant_text,
                    &mut assistant_phase,
                    &mut assistant_reasoning_content,
                    &mut assistant_tool_calls,
                );
                if let Some(call_id) = event.payload.get("tool_call_id").and_then(Value::as_str) {
                    if !emitted_tool_messages.contains(call_id) {
                        let name = event
                            .payload
                            .get("name")
                            .and_then(Value::as_str)
                            .unwrap_or("tool");
                        let error = event
                            .payload
                            .get("error")
                            .and_then(Value::as_str)
                            .unwrap_or("tool failed");
                        messages.push(serde_json::json!({
                            "role": "tool",
                            "tool_call_id": call_id,
                            "name": name,
                            "content": format!("{name} failed: {error}"),
                        }));
                        emitted_tool_messages.insert(call_id.to_string());
                        turn_open = true;
                    }
                }
            }
            "tool.finished" => {
                if suppress_terminal_tail {
                    continue;
                }
                flush_assistant(
                    messages,
                    &mut assistant_text,
                    &mut assistant_phase,
                    &mut assistant_reasoning_content,
                    &mut assistant_tool_calls,
                );
                if let Some(call_id) = event.payload.get("tool_call_id").and_then(Value::as_str) {
                    if !emitted_tool_messages.contains(call_id) {
                        let name = event
                            .payload
                            .get("name")
                            .and_then(Value::as_str)
                            .or_else(|| tool_names.get(call_id).map(String::as_str))
                            .unwrap_or("tool");
                        messages.push(serde_json::json!({
                            "role": "tool",
                            "tool_call_id": call_id,
                            "name": name,
                            "content": synthetic_tool_result_text(name),
                        }));
                        emitted_tool_messages.insert(call_id.to_string());
                        turn_open = true;
                    }
                }
            }
            "session.cancelled" => {
                let should_insert_marker =
                    turn_open || !assistant_text.is_empty() || !assistant_tool_calls.is_empty();
                flush_assistant(
                    messages,
                    &mut assistant_text,
                    &mut assistant_phase,
                    &mut assistant_reasoning_content,
                    &mut assistant_tool_calls,
                );
                if should_insert_marker {
                    messages.push(turn_aborted_user_message());
                }
                turn_open = false;
                suppress_terminal_tail = true;
            }
            "session.done" | "session.failed" => {
                flush_assistant(
                    messages,
                    &mut assistant_text,
                    &mut assistant_phase,
                    &mut assistant_reasoning_content,
                    &mut assistant_tool_calls,
                );
                turn_open = false;
                suppress_terminal_tail = true;
            }
            _ => {}
        }
    }
    flush_assistant(
        messages,
        &mut assistant_text,
        &mut assistant_phase,
        &mut assistant_reasoning_content,
        &mut assistant_tool_calls,
    );
    if !emitted_initial_context_messages {
        messages.append(&mut initial_context_messages);
    }
    normalize_provider_messages(messages);
    std::mem::take(messages)
}

fn initial_context_messages_from_events(
    events: &[EventRecord],
    first_user_message_seq: Option<i64>,
    include_all_anchored: bool,
    inject_default_permissions: bool,
) -> Vec<Value> {
    initial_context_messages_from_iter(
        events.iter(),
        first_user_message_seq,
        include_all_anchored,
        inject_default_permissions,
    )
}

fn initial_context_messages_from_iter<'a, I>(
    events: I,
    first_user_message_seq: Option<i64>,
    include_all_anchored: bool,
    inject_default_permissions: bool,
) -> Vec<Value>
where
    I: IntoIterator<Item = &'a EventRecord>,
{
    let mut context_messages = Vec::new();
    let mut saw_permissions = false;
    for event in events {
        if event.event_type != "workspace.context" {
            continue;
        }
        if let Some(before_seq) = event.payload.get("before_seq").and_then(Value::as_i64) {
            if !include_all_anchored {
                match first_user_message_seq {
                    Some(first_user_message_seq) if before_seq == first_user_message_seq => {}
                    _ => continue,
                }
            }
        }
        let Some(kind) = event.payload.get("kind").and_then(Value::as_str) else {
            continue;
        };
        if kind == WORKSPACE_CONTEXT_PERMISSIONS_KIND
            && event
                .payload
                .get("suppressed")
                .and_then(Value::as_bool)
                .unwrap_or(false)
        {
            saw_permissions = true;
            continue;
        }
        let Some(content) = event.payload.get("content").and_then(Value::as_str) else {
            continue;
        };
        match kind {
            WORKSPACE_CONTEXT_PERMISSIONS_KIND => {
                saw_permissions = true;
                context_messages.push(permissions_context_message(content.to_string()));
            }
            WORKSPACE_CONTEXT_MULTI_AGENT_USAGE_HINT_KIND => {
                context_messages.push(multi_agent_usage_hint_context_message(content.to_string()));
            }
            WORKSPACE_CONTEXT_AGENTS_KIND
            | WORKSPACE_CONTEXT_ENVIRONMENT_KIND
            | WORKSPACE_CONTEXT_USER_SHELL_KIND => {
                context_messages.push(workspace_context_message(vec![content.to_string()]));
            }
            _ => {}
        }
    }
    if inject_default_permissions && !saw_permissions {
        context_messages.insert(
            0,
            permissions_context_message(default_permissions_instructions().to_string()),
        );
    }
    move_workspace_context_before_first_user_message(&mut context_messages);
    context_messages
}

fn workspace_context_message(sections: Vec<String>) -> Value {
    let content = sections
        .into_iter()
        .map(|text| {
            serde_json::json!({
                "type": "input_text",
                "text": text,
            })
        })
        .collect::<Vec<_>>();
    serde_json::json!({
        "role": "user",
        "name": WORKSPACE_CONTEXT_MESSAGE_NAME,
        "content": content,
    })
}

fn workspace_context_message_from_payload(payload: &Value) -> Option<Value> {
    let kind = payload.get("kind").and_then(Value::as_str)?;
    if !matches!(
        kind,
        WORKSPACE_CONTEXT_PERMISSIONS_KIND
            | WORKSPACE_CONTEXT_MULTI_AGENT_USAGE_HINT_KIND
            | WORKSPACE_CONTEXT_AGENTS_KIND
            | WORKSPACE_CONTEXT_ENVIRONMENT_KIND
            | WORKSPACE_CONTEXT_USER_SHELL_KIND
    ) {
        return None;
    }
    let content = payload
        .get("content")
        .and_then(Value::as_str)
        .filter(|content| !content.is_empty())?;
    match kind {
        WORKSPACE_CONTEXT_PERMISSIONS_KIND => {
            Some(permissions_context_message(content.to_string()))
        }
        WORKSPACE_CONTEXT_MULTI_AGENT_USAGE_HINT_KIND => {
            Some(multi_agent_usage_hint_context_message(content.to_string()))
        }
        _ => Some(workspace_context_message(vec![content.to_string()])),
    }
}

fn turn_aborted_user_message() -> Value {
    serde_json::json!({
        "role": "user",
        "content": format!(
            "{TURN_ABORTED_START_MARKER}\n{TURN_ABORTED_INTERRUPTED_GUIDANCE}\n{TURN_ABORTED_END_MARKER}"
        ),
    })
}

fn is_turn_aborted_message(message: &Value) -> bool {
    matches!(
        message.get("role").and_then(Value::as_str),
        Some("user") | Some("developer")
    ) && is_turn_aborted_text(&message_content_text(message))
}

fn is_turn_aborted_text(text: &str) -> bool {
    let trimmed_start = text.trim_start();
    let starts_with_marker = trimmed_start
        .get(..TURN_ABORTED_START_MARKER.len())
        .is_some_and(|candidate| candidate.eq_ignore_ascii_case(TURN_ABORTED_START_MARKER));
    let trimmed_end = trimmed_start.trim_end();
    let ends_with_marker = trimmed_end
        .get(
            trimmed_end
                .len()
                .saturating_sub(TURN_ABORTED_END_MARKER.len())..,
        )
        .is_some_and(|candidate| candidate.eq_ignore_ascii_case(TURN_ABORTED_END_MARKER));
    starts_with_marker && ends_with_marker
}

