fn dispatch_tool_search_tool(
    store: &Store,
    session: &browser_use_protocol::SessionMeta,
    call: &ToolCall,
    tool_router: &ToolRouter,
) -> Result<ToolDispatchOutcome> {
    let query = call
        .arguments
        .get("query")
        .and_then(Value::as_str)
        .unwrap_or_default()
        .trim();
    if query.is_empty() {
        return dispatch_tool_validation_error(store, session, call, "query must not be empty");
    }
    let limit = call
        .arguments
        .get("limit")
        .and_then(Value::as_u64)
        .unwrap_or(8);
    if limit == 0 {
        return dispatch_tool_validation_error(
            store,
            session,
            call,
            "limit must be greater than zero",
        );
    }
    store.append_event(
        &session.id,
        "tool.started",
        serde_json::json!({
            "name": "tool_search",
            "tool_call_id": call.id,
            "arguments": call.arguments,
        }),
    )?;
    let tools = tool_router.search_deferred_tools(query, limit as usize);
    let item = serde_json::json!({
        "type": "tool_search_output",
        "call_id": call.id,
        "status": "completed",
        "execution": "client",
        "tools": tools,
    });
    store.append_event(
        &session.id,
        MODEL_RESPONSE_INPUT_ITEM_EVENT,
        serde_json::json!({
            "source": "tool_search",
            "name": "tool_search",
            "call_id": call.id,
            "item": item,
        }),
    )?;
    store.append_event(
        &session.id,
        "tool.finished",
        serde_json::json!({
            "name": "tool_search",
            "tool_call_id": call.id,
        }),
    )?;
    Ok(ToolDispatchOutcome {
        finished: false,
        messages: vec![item],
    })
}

mod goals;
pub(crate) use goals::*;

pub(crate) fn escape_xml_text(input: &str) -> String {
    input
        .replace('&', "&amp;")
        .replace('<', "&lt;")
        .replace('>', "&gt;")
}

fn dispatch_get_goal_tool(
    store: &Store,
    session: &browser_use_protocol::SessionMeta,
    call: &ToolCall,
) -> Result<ToolDispatchOutcome> {
    if let Err(error) = validate_tool_arguments_object(&call.arguments, "get_goal", &[]) {
        return dispatch_tool_validation_error(store, session, call, &error);
    }
    store.append_event(
        &session.id,
        "tool.started",
        serde_json::json!({
            "name": "get_goal",
            "tool_call_id": call.id,
            "arguments": call.arguments,
        }),
    )?;
    let events = store.events_for_session(&session.id)?;
    let payload = latest_thread_goal_from_events(&events)
        .map(|goal| goal_snapshot_payload(&session.id, &events, &goal, false))
        .unwrap_or(Value::Null);
    store.append_event(
        &session.id,
        "tool.finished",
        serde_json::json!({
            "name": "get_goal",
            "tool_call_id": call.id,
        }),
    )?;
    Ok(ToolDispatchOutcome {
        finished: false,
        messages: vec![tool_json_message(
            store, session, call, "get_goal", payload,
        )?],
    })
}

fn dispatch_create_goal_tool(
    store: &Store,
    session: &browser_use_protocol::SessionMeta,
    call: &ToolCall,
) -> Result<ToolDispatchOutcome> {
    if let Err(error) = validate_tool_arguments_object(
        &call.arguments,
        "create_goal",
        &["objective", "token_budget"],
    ) {
        return dispatch_tool_validation_error(store, session, call, &error);
    }
    let objective = call
        .arguments
        .get("objective")
        .and_then(Value::as_str)
        .unwrap_or_default()
        .trim();
    if objective.is_empty() {
        return dispatch_tool_validation_error(
            store,
            session,
            call,
            "create_goal requires objective",
        );
    }
    let token_budget = match call.arguments.get("token_budget").and_then(Value::as_i64) {
        Some(value) if value > 0 => Some(value),
        Some(_) => {
            return dispatch_tool_validation_error(
                store,
                session,
                call,
                "goal budgets must be positive when provided",
            )
        }
        None => None,
    };
    let events = store.events_for_session(&session.id)?;
    if latest_thread_goal_from_events(&events).is_some() {
        return dispatch_tool_validation_error(
            store,
            session,
            call,
            "goal already exists; create_goal can only be used once for a thread",
        );
    }
    store.append_event(
        &session.id,
        "tool.started",
        serde_json::json!({
            "name": "create_goal",
            "tool_call_id": call.id,
            "arguments": call.arguments,
        }),
    )?;
    let goal_id = uuid::Uuid::new_v4().to_string();
    store.append_event(
        &session.id,
        GOAL_CREATED_EVENT,
        serde_json::json!({
            "goal_id": goal_id,
            "objective": objective,
            "status": "active",
            "token_budget": token_budget,
            "baseline_total_token_usage": latest_codex_total_token_usage_from_events(&events),
            "created_at_ms": now_ms(),
            "tool_call_id": call.id,
        }),
    )?;
    let events = store.events_for_session(&session.id)?;
    let payload = latest_thread_goal_from_events(&events)
        .map(|goal| goal_snapshot_payload(&session.id, &events, &goal, false))
        .unwrap_or(Value::Null);
    store.append_event(
        &session.id,
        "tool.finished",
        serde_json::json!({
            "name": "create_goal",
            "tool_call_id": call.id,
        }),
    )?;
    Ok(ToolDispatchOutcome {
        finished: false,
        messages: vec![tool_json_message(
            store,
            session,
            call,
            "create_goal",
            payload,
        )?],
    })
}

fn dispatch_update_goal_tool(
    store: &Store,
    session: &browser_use_protocol::SessionMeta,
    call: &ToolCall,
) -> Result<ToolDispatchOutcome> {
    if let Err(error) = validate_tool_arguments_object(&call.arguments, "update_goal", &["status"])
    {
        return dispatch_tool_validation_error(store, session, call, &error);
    }
    let status = call
        .arguments
        .get("status")
        .and_then(Value::as_str)
        .unwrap_or_default()
        .trim();
    if !matches!(status, "complete" | "blocked") {
        return dispatch_tool_validation_error(
            store,
            session,
            call,
            "update_goal status must be complete or blocked",
        );
    }
    let events = store.events_for_session(&session.id)?;
    let Some(goal) = latest_thread_goal_from_events(&events) else {
        return dispatch_tool_validation_error(store, session, call, "no active goal exists");
    };
    if !matches!(goal.status.as_str(), "active" | "budget_limited") {
        return dispatch_tool_validation_error(store, session, call, "goal is not active");
    }
    let stored_status = if goal.status == "budget_limited" && status == "blocked" {
        "budget_limited"
    } else {
        status
    };
    store.append_event(
        &session.id,
        "tool.started",
        serde_json::json!({
            "name": "update_goal",
            "tool_call_id": call.id,
            "arguments": call.arguments,
        }),
    )?;
    store.append_event(
        &session.id,
        GOAL_UPDATED_EVENT,
        serde_json::json!({
            "goal_id": goal.goal_id,
            "status": stored_status,
            "updated_at_ms": now_ms(),
            "tool_call_id": call.id,
            "requested_status": status,
        }),
    )?;
    let events = store.events_for_session(&session.id)?;
    let payload = latest_thread_goal_from_events(&events)
        .map(|goal| {
            goal_snapshot_payload(
                &session.id,
                &events,
                &goal,
                status == "complete" && stored_status == "complete",
            )
        })
        .unwrap_or(Value::Null);
    store.append_event(
        &session.id,
        "tool.finished",
        serde_json::json!({
            "name": "update_goal",
            "tool_call_id": call.id,
        }),
    )?;
    Ok(ToolDispatchOutcome {
        finished: false,
        messages: vec![tool_json_message(
            store,
            session,
            call,
            "update_goal",
            payload,
        )?],
    })
}

