fn agents_md_context_for_cwd_with_options(
    cwd: &Path,
    config_profile: Option<&str>,
    config_overrides: &[(String, toml::Value)],
) -> Result<Option<AgentsMdContext>> {
    Ok(load_agents_md_context_for_cwd_with_options(cwd, config_profile, config_overrides)?.context)
}

#[cfg(test)]
fn load_agents_md_context_for_cwd_with_options(
    cwd: &Path,
    config_profile: Option<&str>,
    config_overrides: &[(String, toml::Value)],
) -> Result<AgentsMdLoad> {
    load_agents_md_context_for_cwd_with_thread_config(cwd, config_profile, config_overrides, None)
}

fn load_agents_md_context_for_cwd_with_run_options(
    cwd: &Path,
    options: &AgentRunOptions,
) -> Result<AgentsMdLoad> {
    load_agents_md_context_for_cwd_with_thread_config(
        cwd,
        options.config_profile.as_deref(),
        &options.config_overrides,
        options.session_thread_config.as_ref(),
    )
}

fn load_agents_md_context_for_cwd_with_thread_config(
    cwd: &Path,
    config_profile: Option<&str>,
    config_overrides: &[(String, toml::Value)],
    session_thread_config: Option<&toml::Value>,
) -> Result<AgentsMdLoad> {
    let mut warnings = Vec::new();
    let config = load_agents_md_config_with_thread_config(
        cwd,
        &mut warnings,
        config_profile,
        config_overrides,
        session_thread_config,
    )?;
    let mut sources = Vec::new();
    let mut parts = Vec::new();
    if let Some((path, text)) = load_global_agents_md(&mut warnings) {
        sources.push(path.display().to_string());
        parts.push(text);
    }
    match project_agents_md_for_cwd(cwd, &config, &mut warnings) {
        Ok(Some((project_docs, project_sources))) => {
            if !parts.is_empty() {
                parts.push(AGENTS_MD_SEPARATOR.trim().to_string());
            }
            sources.extend(project_sources);
            parts.push(project_docs);
        }
        Ok(None) => {}
        // Codex logs project-doc discovery/read errors and continues without
        // project AGENTS docs. Keep that failure out of model-visible context.
        Err(_error) => {}
    }
    let context = if parts.is_empty() {
        None
    } else {
        let directory = cwd.display().to_string();
        Some(AgentsMdContext {
            content: format!(
                "# AGENTS.md instructions for {directory}\n\n<INSTRUCTIONS>\n{}\n</INSTRUCTIONS>",
                parts.join("\n\n")
            ),
            #[cfg(test)]
            sources: sources.clone(),
            #[cfg(test)]
            warnings: warnings.clone(),
        })
    };
    let base_instructions = config.base_instructions()?;
    let app_home = browser_use_terminal_home_dir();
    let rendered_skills = render_available_skills_instructions(app_home.as_deref(), cwd, &config);
    let skills_instructions = rendered_skills
        .as_ref()
        .map(|rendered| rendered.content.clone());
    if let Some(warning) = rendered_skills.and_then(|rendered| rendered.warning) {
        warnings.push(warning);
    }
    let memory_instructions =
        render_memory_context_instructions(app_home.as_deref(), config.memories_enabled);
    let plugin_summaries = browser_use_terminal_plugin_capability_summaries_for_config(&config);
    let plugins_instructions = render_available_plugins_instructions(&plugin_summaries);
    Ok(AgentsMdLoad {
        context,
        sources,
        warnings,
        base_instructions,
        developer_instructions: config.developer_instructions,
        include_permissions_instructions: config.include_permissions_instructions,
        include_collaboration_mode_instructions: config.include_collaboration_mode_instructions,
        include_environment_context: config.include_environment_context,
        multi_agent_enabled: config.multi_agent_enabled,
        multi_agent_v2: config.multi_agent_v2,
        skills_instructions,
        memory_instructions,
        plugins_instructions,
    })
}

