fn load_agents_md_config(
    cwd: &Path,
    warnings: &mut Vec<String>,
    config_profile: Option<&str>,
    config_overrides: &[(String, toml::Value)],
) -> Result<AgentsMdConfig> {
    load_agents_md_config_with_thread_config(cwd, warnings, config_profile, config_overrides, None)
}

fn load_agents_md_config_for_options(
    cwd: &Path,
    warnings: &mut Vec<String>,
    options: &AgentRunOptions,
) -> Result<AgentsMdConfig> {
    load_agents_md_config_with_thread_config(
        cwd,
        warnings,
        options.config_profile.as_deref(),
        &options.config_overrides,
        options.session_thread_config.as_ref(),
    )
}

fn load_agents_md_config_with_thread_config(
    cwd: &Path,
    warnings: &mut Vec<String>,
    config_profile: Option<&str>,
    config_overrides: &[(String, toml::Value)],
    session_thread_config: Option<&toml::Value>,
) -> Result<AgentsMdConfig> {
    let mut config = AgentsMdConfig::default();
    if let Some(profile) = config_profile {
        validate_browser_use_terminal_config_profile_name(profile)?;
    }
    let session_overrides_layer =
        (!config_overrides.is_empty()).then(|| build_config_overrides_layer(config_overrides));
    let Some(base) = browser_use_terminal_home_dir() else {
        if let Some(session_overrides_layer) = session_overrides_layer.as_ref() {
            apply_agents_md_config_layer(
                &mut config,
                session_overrides_layer,
                Path::new("session config overrides"),
                cwd,
                ConfigLayerKind::NonProject,
                warnings,
            )?;
        }
        if let Some(session_thread_config) = session_thread_config {
            apply_session_thread_config_layer(&mut config, session_thread_config, cwd, warnings)?;
        }
        return Ok(config);
    };
    let mut pre_project_config = toml::Value::Table(toml::map::Map::new());

    if let Some(config_path) = system_browser_use_terminal_config_path() {
        if let Some(value) = read_browser_use_terminal_config_toml(&config_path)? {
            apply_agents_md_config_layer(
                &mut config,
                &value,
                &config_path,
                config_file_relative_base(&config_path),
                ConfigLayerKind::NonProject,
                warnings,
            )?;
            merge_toml_value(&mut pre_project_config, &value);
        }
    }

    let user_config_path = base.join(BROWSER_USE_TERMINAL_CONFIG_FILENAME);
    if let Some(value) = read_browser_use_terminal_config_toml(&user_config_path)? {
        if let Some(profile) = config_profile {
            reject_legacy_profile_conflict(&value, profile, &user_config_path)?;
        }
        apply_agents_md_config_layer(
            &mut config,
            &value,
            &user_config_path,
            config_file_relative_base(&user_config_path),
            ConfigLayerKind::NonProject,
            warnings,
        )?;
        merge_toml_value(&mut pre_project_config, &value);
    }

    if let Some(profile) = config_profile {
        let profile_config_path = browser_use_terminal_profile_config_path(&base, profile);
        if let Some(value) = read_browser_use_terminal_config_toml(&profile_config_path)? {
            apply_agents_md_config_layer(
                &mut config,
                &value,
                &profile_config_path,
                config_file_relative_base(&profile_config_path),
                ConfigLayerKind::NonProject,
                warnings,
            )?;
            merge_toml_value(&mut pre_project_config, &value);
        }
    }

    let mut discovery_config = config.clone();
    if let Some(session_overrides_layer) = session_overrides_layer.as_ref() {
        apply_agents_md_config_layer(
            &mut discovery_config,
            session_overrides_layer,
            Path::new("session config overrides"),
            cwd,
            ConfigLayerKind::NonProject,
            warnings,
        )?;
        merge_toml_value(&mut pre_project_config, session_overrides_layer);
    }

    load_project_agents_md_config_layers(
        cwd,
        &base,
        &pre_project_config,
        &discovery_config.project_root_markers,
        &mut config,
        warnings,
    )?;

    if let Some(session_overrides_layer) = session_overrides_layer.as_ref() {
        apply_agents_md_config_layer(
            &mut config,
            session_overrides_layer,
            Path::new("session config overrides"),
            cwd,
            ConfigLayerKind::NonProject,
            warnings,
        )?;
    }

    if let Some(session_thread_config) = session_thread_config {
        apply_session_thread_config_layer(&mut config, session_thread_config, cwd, warnings)?;
    }

    let managed_config_path = managed_browser_use_terminal_config_path(&base);
    if let Some(managed_config) = read_browser_use_terminal_config_toml(&managed_config_path)? {
        apply_agents_md_config_layer(
            &mut config,
            &managed_config,
            &managed_config_path,
            config_file_relative_base(&managed_config_path),
            ConfigLayerKind::NonProject,
            warnings,
        )?;
    }
    if let Some(managed_preferences_config) =
        read_browser_use_terminal_managed_preferences_config_toml()?
    {
        apply_agents_md_config_layer(
            &mut config,
            &managed_preferences_config,
            Path::new(BROWSER_USE_TERMINAL_MANAGED_PREFERENCES_CONFIG_SOURCE),
            cwd,
            ConfigLayerKind::NonProject,
            warnings,
        )?;
    }
    apply_enabled_plugin_mcp_servers_config_layer(&mut config, warnings)?;
    apply_enabled_plugin_hooks_config_layer(&mut config, warnings)?;
    if config.model_catalog.is_none() {
        if let Some(snapshot) = load_fresh_models_cache(&base) {
            config.model_catalog = Some(snapshot.catalog);
            config.model_catalog_cache_etag = snapshot.etag;
        }
    }
    Ok(config)
}

fn build_config_overrides_layer(config_overrides: &[(String, toml::Value)]) -> toml::Value {
    let mut root = toml::Value::Table(toml::map::Map::new());
    for (path, value) in config_overrides {
        apply_toml_override(&mut root, path, value.clone());
    }
    root
}

fn apply_session_thread_config_layer(
    config: &mut AgentsMdConfig,
    value: &toml::Value,
    cwd: &Path,
    warnings: &mut Vec<String>,
) -> Result<()> {
    let Some(table) = value.as_table() else {
        bail!("Invalid session thread config: expected a TOML table.");
    };
    validate_session_thread_config_features(value)?;
    if table.is_empty() {
        return Ok(());
    }
    apply_agents_md_config_layer(
        config,
        value,
        Path::new("session thread config"),
        cwd,
        ConfigLayerKind::NonProject,
        warnings,
    )
}

fn validate_session_thread_config_features(value: &toml::Value) -> Result<()> {
    let Some(features) = value.get("features") else {
        return Ok(());
    };
    let Some(features) = features.as_table() else {
        bail!("Invalid session thread config `features`: expected a table.");
    };
    for (key, value) in features {
        if !value.is_bool() {
            bail!("Invalid session thread config `features.{key}`: expected a boolean.");
        }
    }
    Ok(())
}

fn apply_toml_override(root: &mut toml::Value, path: &str, value: toml::Value) {
    let mut current = root;
    let mut segments = path.split('.').peekable();
    while let Some(segment) = segments.next() {
        let is_last = segments.peek().is_none();
        if is_last {
            match current {
                toml::Value::Table(table) => {
                    table.insert(segment.to_string(), value);
                }
                _ => {
                    let mut table = toml::map::Map::new();
                    table.insert(segment.to_string(), value);
                    *current = toml::Value::Table(table);
                }
            }
            return;
        }
        match current {
            toml::Value::Table(table) => {
                current = table
                    .entry(segment.to_string())
                    .or_insert_with(|| toml::Value::Table(toml::map::Map::new()));
            }
            _ => {
                *current = toml::Value::Table(toml::map::Map::new());
                if let toml::Value::Table(table) = current {
                    current = table
                        .entry(segment.to_string())
                        .or_insert_with(|| toml::Value::Table(toml::map::Map::new()));
                }
            }
        }
    }
}

fn browser_use_terminal_profile_config_path(app_home: &Path, profile: &str) -> PathBuf {
    app_home.join(format!(
        "{profile}{BROWSER_USE_TERMINAL_PROFILE_CONFIG_SUFFIX}"
    ))
}

fn validate_browser_use_terminal_config_profile_name(profile: &str) -> Result<()> {
    if profile.is_empty()
        || !profile
            .bytes()
            .all(|byte| byte.is_ascii_alphanumeric() || matches!(byte, b'_' | b'-'))
    {
        bail!("invalid --profile value `{profile}`; pass a plain name such as `work`");
    }
    Ok(())
}

fn reject_legacy_profile_conflict(value: &toml::Value, profile: &str, path: &Path) -> Result<()> {
    let legacy_profile_is_selected = value
        .get("profile")
        .and_then(toml::Value::as_str)
        .is_some_and(|selected| selected == profile);
    let legacy_profile_table_exists = value
        .get("profiles")
        .and_then(toml::Value::as_table)
        .is_some_and(|profiles| profiles.contains_key(profile));
    if legacy_profile_is_selected || legacy_profile_table_exists {
        let active_profile_path = browser_use_terminal_profile_config_path(
            path.parent().unwrap_or_else(|| Path::new("")),
            profile,
        );
        bail!(
            "--profile `{profile}` cannot be used while {} contains legacy `profile = \"{profile}\"` or `[profiles.{profile}]` config; move those settings into {} and remove the legacy profile selector/table.",
            path.display(),
            active_profile_path.display()
        );
    }
    Ok(())
}

