    fn spawn_models_server(
        body: String,
        etag: &str,
    ) -> Result<(
        String,
        std::sync::mpsc::Receiver<String>,
        std::thread::JoinHandle<()>,
    )> {
        let listener = std::net::TcpListener::bind("127.0.0.1:0")?;
        let addr = listener.local_addr()?;
        let (tx, rx) = std::sync::mpsc::channel();
        let etag = etag.to_string();
        let handle = std::thread::spawn(move || {
            if let Ok((mut stream, _)) = listener.accept() {
                let mut request = Vec::new();
                let mut buffer = [0_u8; 8192];
                if let Ok(n) = std::io::Read::read(&mut stream, &mut buffer) {
                    request.extend_from_slice(&buffer[..n]);
                }
                let _ = tx.send(String::from_utf8_lossy(&request).to_string());
                let response = format!(
                    "HTTP/1.1 200 OK\r\ncontent-type: application/json\r\netag: {etag}\r\ncontent-length: {}\r\nconnection: close\r\n\r\n{body}",
                    body.len()
                );
                let _ = std::io::Write::write_all(&mut stream, response.as_bytes());
            }
        });
        Ok((format!("http://{addr}"), rx, handle))
    }

    #[derive(Debug)]
    struct CapturedResponsesRequest {
        request_line: String,
        headers: String,
    }

    fn responses_completed_sse(response_id: &str, text: &str) -> String {
        serde_json::json!({
            "type": "response.completed",
            "response": {
                "id": response_id,
                "output": [{
                    "type": "message",
                    "role": "assistant",
                    "content": [{"type": "output_text", "text": text}],
                }],
                "usage": {"input_tokens": 1, "output_tokens": 1, "total_tokens": 2},
            },
        })
        .to_string()
    }

    fn responses_sse_body(response_id: &str, text: &str) -> String {
        format!("data: {}\n\n", responses_completed_sse(response_id, text))
    }

    fn spawn_responses_capture_server_sequence(
        bodies: Vec<String>,
        accept_timeout: Duration,
    ) -> Result<(
        String,
        std::sync::mpsc::Receiver<CapturedResponsesRequest>,
        std::thread::JoinHandle<usize>,
    )> {
        let listener = std::net::TcpListener::bind("127.0.0.1:0")?;
        listener.set_nonblocking(true)?;
        let addr = listener.local_addr()?;
        let (tx, rx) = std::sync::mpsc::channel();
        let handle = std::thread::spawn(move || {
            let mut served = 0;
            for body in bodies {
                let started = Instant::now();
                let (mut stream, _) = loop {
                    match listener.accept() {
                        Ok(accepted) => break accepted,
                        Err(error) if error.kind() == std::io::ErrorKind::WouldBlock => {
                            if started.elapsed() >= accept_timeout {
                                return served;
                            }
                            std::thread::sleep(Duration::from_millis(5));
                        }
                        Err(error) => panic!("accept responses request: {error}"),
                    }
                };
                let mut request = Vec::new();
                let mut buffer = [0_u8; 8192];
                stream
                    .set_nonblocking(false)
                    .expect("use blocking responses request stream");
                let header_end = loop {
                    let read = std::io::Read::read(&mut stream, &mut buffer)
                        .expect("read responses request");
                    if read == 0 {
                        panic!("responses request ended before headers");
                    }
                    request.extend_from_slice(&buffer[..read]);
                    if let Some(pos) = request
                        .windows(4)
                        .position(|window| window == b"\r\n\r\n")
                        .map(|pos| pos + 4)
                    {
                        break pos;
                    }
                };
                let headers = String::from_utf8_lossy(&request[..header_end]).to_string();
                let headers_lower = headers.to_ascii_lowercase();
                let content_length = headers_lower
                    .lines()
                    .find_map(|line| line.strip_prefix("content-length: "))
                    .and_then(|value| value.trim().parse::<usize>().ok())
                    .unwrap_or(0);
                while request.len() < header_end + content_length {
                    let read = std::io::Read::read(&mut stream, &mut buffer)
                        .expect("read responses request body");
                    if read == 0 {
                        break;
                    }
                    request.extend_from_slice(&buffer[..read]);
                }
                let request_line = headers.lines().next().unwrap_or_default().to_string();
                tx.send(CapturedResponsesRequest {
                    request_line,
                    headers,
                })
                .expect("send captured responses request");
                let response = format!(
                    "HTTP/1.1 200 OK\r\ncontent-type: text/event-stream\r\ncontent-length: {}\r\nconnection: close\r\n\r\n{body}",
                    body.len()
                );
                std::io::Write::write_all(&mut stream, response.as_bytes())
                    .expect("write responses response");
                served += 1;
            }
            served
        });
        Ok((format!("http://{addr}/v1"), rx, handle))
    }

    fn write_corp_responses_provider_config(
        app_home: &Path,
        base_url: &str,
        api_version: &str,
        static_header: &str,
    ) -> Result<()> {
        std::fs::write(
            app_home.join("config.toml"),
            format!(
                r#"
model_provider = "corp"

[model_providers.corp]
name = "Corp"
base_url = "{base_url}"
wire_api = "responses"
request_max_retries = 0
stream_max_retries = 0
stream_idle_timeout_ms = 5000
websocket_connect_timeout_ms = 15000
requires_openai_auth = false
supports_websockets = true

[model_providers.corp.query_params]
api-version = "{api_version}"

[model_providers.corp.http_headers]
x-static = "{static_header}"

[model_providers.corp.env_http_headers]
x-env = "CORP_HEADER"
"#,
            ),
        )?;
        Ok(())
    }

    fn event(event_type: &str, payload: Value) -> EventRecord {
        EventRecord {
            seq: 0,
            id: format!("event-{event_type}"),
            session_id: "session-test".to_string(),
            ts_ms: 0,
            event_type: event_type.to_string(),
            payload,
        }
    }

    #[test]
    fn task_analytics_summary_rolls_up_usage_and_tool_names() {
        let summary = task_analytics_summary_from_events(&[
            event(
                "model.usage",
                json!({
                    "input_tokens": 100,
                    "input_cached_tokens": 40,
                    "input_cache_creation_tokens": 10,
                    "output_tokens": 25,
                }),
            ),
            event(
                "model.usage",
                json!({
                    "input_tokens": 50,
                    "output_tokens": 10,
                    "total_tokens": 80,
                }),
            ),
            event(
                "model.tool_call",
                json!({
                    "id": "call-1",
                    "name": "exec_command",
                    "arguments": {"cmd": "secret command"},
                }),
            ),
            event(
                "model.tool_call",
                json!({
                    "id": "call-2",
                    "name": "read_file",
                    "arguments": {"path": "/private/file"},
                }),
            ),
            event(
                "model.tool_call",
                json!({
                    "id": "call-3",
                    "name": "exec_command",
                    "arguments": {"cmd": "another secret command"},
                }),
            ),
        ]);

        assert_eq!(summary["model_invocation_count"], 2);
        assert_eq!(summary["input_tokens"], 150);
        assert_eq!(summary["input_cached_tokens"], 40);
        assert_eq!(summary["input_cache_creation_tokens"], 10);
        assert_eq!(summary["output_tokens"], 35);
        assert_eq!(summary["total_tokens"], 205);
        assert_eq!(summary["tool_call_count"], 3);
        assert_eq!(summary["unique_tool_count"], 2);
        assert_eq!(summary["tool_names"], json!(["exec_command", "read_file"]));
        assert_eq!(summary["tool_counts"]["exec_command"], 2);
        assert_eq!(summary["tool_counts"]["read_file"], 1);
        assert!(summary.to_string().contains("exec_command"));
        assert!(!summary.to_string().contains("secret command"));
        assert!(!summary.to_string().contains("/private/file"));
    }

    #[test]
    fn browser_preference_commands_persist_mode_and_domain_profile() -> Result<()> {
        let temp = tempfile::tempdir()?;
        let store = Store::open(temp.path())?;
        let session = store.create_session(None, temp.path())?;

        let output = dispatch_browser_preference_command_for_mode(
            &store,
            &session,
            "browser preference use cloud",
            None,
        )?
        .expect("preference command");
        assert_eq!(output["status"], "ok");
        assert_eq!(
            store.get_setting(BROWSER_PREF_MODE)?.as_deref(),
            Some("cloud")
        );
        assert_eq!(
            store.get_setting("browser")?.as_deref(),
            Some("Browser Use cloud")
        );
        assert_eq!(
            resolve_browser_command_for_selected_mode(&store, "browser connect", None)?,
            "browser remote start"
        );

        let output = dispatch_browser_preference_command_for_mode(
            &store,
            &session,
            "browser profile remember --domain https://www.gusto.com/ --profile 'google-chrome:Profile 2' --mode local",
            None,
        )?
        .expect("profile command");
        assert_eq!(output["status"], "ok");
        assert_eq!(output["remembered"]["domain"], "gusto.com");
        assert_eq!(
            remembered_domain_profile(&store, "gusto.com")?
                .and_then(|value| value["profile_id"].as_str().map(ToOwned::to_owned))
                .as_deref(),
            Some("google-chrome:Profile 2")
        );
        assert!(output["next_step"]
            .as_str()
            .unwrap()
            .contains("browser local setup --profile 'google-chrome:Profile 2'"));
        assert_eq!(
            resolve_browser_command_for_selected_mode(&store, "connect", None)?,
            "browser connect local"
        );

        dispatch_browser_preference_command_for_mode(
            &store,
            &session,
            "browser profile remember --domain browser-use.com --profile 'cloud profile id' --mode cloud",
            None,
        )?
        .expect("cloud profile command");
        assert_eq!(
            resolve_browser_command_for_selected_mode(&store, "browser connect", None)?,
            "browser remote start --profile-id 'cloud profile id'"
        );
        Ok(())
    }

    #[test]
    fn selected_browser_mode_resolves_default_connect_and_blocks_mismatches() -> Result<()> {
        let temp = tempfile::tempdir()?;
        let store = Store::open(temp.path())?;
        let session = store.create_session(None, temp.path())?;

        store.set_setting("browser", "Browser Use cloud")?;
        assert_eq!(
            resolve_browser_command_for_selected_mode(&store, "browser connect", None)?,
            "browser remote start"
        );
        store.set_setting(BROWSER_PREF_PROFILE, "google-chrome:Profile 2")?;
        assert_eq!(
            resolve_browser_command_for_selected_mode(&store, "browser connect", Some("cloud"))?,
            "browser remote start"
        );
        assert_eq!(
            resolve_browser_command_for_selected_mode(&store, "browser connect", Some("local"))?,
            "browser connect local"
        );
        assert_eq!(
            resolve_browser_command_for_selected_mode(
                &store,
                "browser connect",
                Some("managed-headless"),
            )?,
            "browser connect managed --headless"
        );

        let cloud_local = resolve_browser_command_for_selected_mode(
            &store,
            "browser connect local",
            Some("cloud"),
        )
        .expect_err("cloud mode must reject local connect")
        .to_string();
        assert!(cloud_local.contains("locked to Browser Use cloud"));

        let local_remote = resolve_browser_command_for_selected_mode(
            &store,
            "browser remote start",
            Some("local"),
        )
        .expect_err("local mode must reject remote start")
        .to_string();
        assert!(local_remote.contains("locked to Local Chrome"));

        let headless_headed = resolve_browser_command_for_selected_mode(
            &store,
            "browser connect managed --headed",
            Some("managed-headless"),
        )
        .expect_err("headless mode must reject headed managed browser")
        .to_string();
        assert!(headless_headed.contains("locked to Headless Chromium"));

        let preference_change = dispatch_browser_preference_command_for_mode(
            &store,
            &session,
            "browser preference use cloud",
            Some("local"),
        )
        .expect_err("locked local mode must reject cloud preference")
        .to_string();
        assert!(preference_change.contains("locked to Local Chrome"));
        Ok(())
    }

