    #[test]
    fn message_history_appends_metadata_and_lookup_like_codex() -> Result<()> {
        let temp = tempfile::tempdir()?;
        let config = MessageHistoryConfig {
            app_home: temp.path().join("codex-home"),
            settings: MessageHistorySettings::default(),
        };

        assert!(append_message_history_entry(
            "first prompt",
            "session-a",
            &config
        )?);
        assert!(append_message_history_entry(
            "second prompt",
            "session-b",
            &config
        )?);

        let (log_id, count) = message_history_metadata(&config);
        assert_ne!(log_id, 0);
        assert_eq!(count, 2);
        assert_eq!(
            lookup_message_history_entry(log_id, 0, &config)
                .context("first history entry")?
                .text,
            "first prompt"
        );
        assert_eq!(
            lookup_message_history_entry(log_id, 1, &config)
                .context("second history entry")?
                .session_id,
            "session-b"
        );
        assert_eq!(
            message_history_entries(log_id, count, &config)
                .into_iter()
                .map(|entry| entry.text)
                .collect::<Vec<_>>(),
            vec!["first prompt".to_string(), "second prompt".to_string()]
        );
        assert!(lookup_message_history_entry(log_id.saturating_add(1), 0, &config).is_none());

        #[cfg(unix)]
        {
            use std::os::unix::fs::PermissionsExt;
            let mode = std::fs::metadata(message_history_path(&config))?
                .permissions()
                .mode()
                & 0o777;
            assert_eq!(mode, 0o600);
        }
        Ok(())
    }

    #[test]
    fn message_history_respects_persistence_none_and_trims_to_newest() -> Result<()> {
        let temp = tempfile::tempdir()?;
        let disabled = MessageHistoryConfig {
            app_home: temp.path().join("disabled"),
            settings: MessageHistorySettings {
                persistence: MessageHistoryPersistence::None,
                max_bytes: None,
            },
        };
        assert!(!append_message_history_entry(
            "skip me", "session", &disabled
        )?);
        assert!(!message_history_path(&disabled).exists());

        let trimmed = MessageHistoryConfig {
            app_home: temp.path().join("trimmed"),
            settings: MessageHistorySettings {
                persistence: MessageHistoryPersistence::SaveAll,
                max_bytes: Some(260),
            },
        };
        for idx in 0..6 {
            append_message_history_entry(
                &format!("prompt-{idx}-{}", "x".repeat(80)),
                "session",
                &trimmed,
            )?;
        }

        let contents = std::fs::read_to_string(message_history_path(&trimmed))?;
        assert!(contents.contains("prompt-5-"));
        assert!(!contents.contains("prompt-0-"));
        assert!(std::fs::metadata(message_history_path(&trimmed))?.len() <= 260);
        Ok(())
    }

    #[test]
    fn provider_turn_reuses_session_config_snapshot_when_defaults_change() -> Result<()> {
        let temp = tempfile::tempdir()?;
        let app_home = create_empty_browser_use_terminal_home(temp.path())?;
        std::fs::write(
            app_home.join("config.toml"),
            "model_reasoning_effort = \"high\"\nmodel_context_window = 12000\nmodel_auto_compact_token_limit = 8000\ntool_output_token_limit = 123\n",
        )?;
        let project = temp.path().join("project");
        std::fs::create_dir_all(project.join(".git"))?;
        let store = Store::open(temp.path().join("state"))?;
        let provider = InstructionCapturingProvider::default();

        let session_id = with_browser_use_terminal_home(&app_home, || -> Result<String> {
            let session_id = run_agent_with_provider(
                &store,
                &provider,
                "capture first config",
                &project,
                AgentRunOptions::default(),
            )?;
            std::fs::write(
                app_home.join("config.toml"),
                "model_reasoning_effort = \"low\"\nmodel_context_window = 5000\nmodel_auto_compact_token_limit = 3000\ntool_output_token_limit = 44\n",
            )?;
            store.append_event(
                &session_id,
                "session.followup",
                serde_json::json!({"text": "capture resumed config"}),
            )?;
            run_existing_session_with_provider(
                &store,
                &provider,
                &session_id,
                AgentRunOptions::default(),
            )?;
            Ok(session_id)
        })?;

        let settings = provider.captured_model_settings();
        assert_eq!(settings.len(), 2);
        assert_eq!(settings[0].reasoning_effort.as_deref(), Some("high"));
        assert_eq!(settings[1].reasoning_effort.as_deref(), Some("high"));

        let infos = provider.captured_model_request_infos();
        assert_eq!(infos.len(), 2);
        let first_info = infos[0].as_ref().context("first model request info")?;
        let resumed_info = infos[1].as_ref().context("resumed model request info")?;
        assert_eq!(first_info.resolved_context_window(), Some(12000));
        assert_eq!(resumed_info.resolved_context_window(), Some(12000));
        assert_eq!(resumed_info.auto_compact_token_limit(), Some(8000));
        assert_eq!(resumed_info.tool_output_token_budget(), 123);

        let events = store.events_for_session(&session_id)?;
        let snapshots = events
            .iter()
            .filter(|event| event.event_type == SESSION_CONFIG_SNAPSHOT_EVENT)
            .collect::<Vec<_>>();
        assert_eq!(snapshots.len(), 2);
        assert_eq!(snapshots[0].payload["model"], provider.model_name());
        assert_eq!(
            snapshots[0].payload["model_provider_id"],
            provider.provider_name()
        );
        assert_eq!(snapshots[0].payload["collaboration_mode"], "default");
        assert_eq!(
            snapshots[0].payload["model_settings"]["reasoning_effort"],
            "high"
        );
        assert_eq!(
            snapshots[0].payload["model_request_info"]["context_window"],
            12000
        );
        Ok(())
    }

