    #[test]
    fn provider_messages_preserve_reasoning_for_tool_call_turns() -> Result<()> {
        let temp = tempfile::tempdir()?;
        let store = Store::open(temp.path())?;
        let session = store.create_session(None, temp.path())?;
        store.append_event(
            &session.id,
            "session.input",
            serde_json::json!({"text": "inspect"}),
        )?;
        store.append_event(
            &session.id,
            "model.thinking_delta",
            serde_json::json!({"text": "Need page state. "}),
        )?;
        store.append_event(
            &session.id,
            "model.thinking_delta",
            serde_json::json!({"text": "Call python."}),
        )?;
        store.append_event(
            &session.id,
            "model.tool_call",
            serde_json::json!({
                "id": "call_py",
                "name": "python",
                "arguments": {"code": "print('ok')"},
            }),
        )?;
        store.append_event(
            &session.id,
            "tool.finished",
            serde_json::json!({
                "name": "python",
                "tool_call_id": "call_py",
            }),
        )?;

        let messages = provider_messages_from_events(&store.events_for_session(&session.id)?);

        assert_eq!(messages[1]["role"], "assistant");
        assert_eq!(messages[1]["tool_calls"][0]["id"], "call_py");
        assert_eq!(
            messages[1]["reasoning_content"],
            "Need page state. Call python."
        );
        assert_eq!(messages[2]["role"], "tool");
        Ok(())
    }

    #[test]
    fn provider_done_tool_finishes_session() -> Result<()> {
        let temp = tempfile::tempdir()?;
        let store = Store::open(temp.path())?;
        let provider = ScriptedProvider::new(vec![vec![
            ModelEvent::ToolCall {
                call: ToolCall {
                    id: "done_1".to_string(),
                    name: "done".to_string(),
                    namespace: None,
                    arguments: serde_json::json!({"result": "final answer"}),
                },
            },
            ModelEvent::Done,
        ]]);
        let session_id = run_agent_with_provider(
            &store,
            &provider,
            "finish directly",
            temp.path(),
            AgentRunOptions::default(),
        )?;
        let events = store.events_for_session(&session_id)?;
        assert!(events.iter().any(|event| event.event_type == "model.config"
            && event.payload["provider"] == "scripted"
            && event.payload["model"] == "scripted"));
        assert!(events
            .iter()
            .any(|event| event.event_type == "tool.finished" && event.payload["name"] == "done"));
        assert!(events
            .iter()
            .any(|event| event.event_type == "session.done"
                && event.payload["result"] == "final answer"));
        let started = events
            .iter()
            .find(|event| event.event_type == CODEX_TURN_STARTED_EVENT)
            .context("missing Codex-shaped turn start event")?;
        assert_eq!(started.payload["turn_id"], started.payload["run_id"]);
        assert_eq!(started.payload["collaboration_mode_kind"], "default");
        let completed = events
            .iter()
            .find(|event| event.event_type == CODEX_TURN_COMPLETE_EVENT)
            .context("missing Codex-shaped turn complete event")?;
        assert_eq!(completed.payload["turn_id"], started.payload["turn_id"]);
        assert_eq!(completed.payload["last_agent_message"], "final answer");
        assert_eq!(completed.payload["status"], "done");
        let runs = store.runs_for_session(&session_id)?;
        assert_eq!(runs.len(), 1);
        assert_eq!(runs[0].status, "done");
        assert!(runs[0].ended_ms.is_some());
        Ok(())
    }

    #[test]
    fn provider_loop_dispatches_configured_stdio_mcp_tool_like_codex() -> Result<()> {
        let temp = tempfile::tempdir()?;
        let codex_home = create_empty_browser_use_terminal_home(temp.path())?;
        let mcp_script = temp.path().join("mcp_echo.py");
        write_test_mcp_echo_server(&mcp_script)?;
        std::fs::write(
            codex_home.join("config.toml"),
            format!(
                r#"
[mcp_servers.docs]
command = "python3"
args = [{}]
startup_timeout_ms = 2000
tool_timeout_ms = 2000
"#,
                toml_basic_string(mcp_script.to_string_lossy().as_ref())
            ),
        )?;

        with_browser_use_terminal_home(&codex_home, || -> Result<()> {
            let store = Store::open(temp.path().join("state"))?;
            let provider = ScriptedProvider::new(vec![
                vec![
                    ModelEvent::ToolCall {
                        call: ToolCall {
                            id: "mcp_1".to_string(),
                            name: "echo_tool".to_string(),
                            namespace: Some("mcp__docs__".to_string()),
                            arguments: serde_json::json!({"text": "hello"}),
                        },
                    },
                    ModelEvent::Done,
                ],
                vec![
                    ModelEvent::TextDelta {
                        text: "final".to_string(),
                    },
                    ModelEvent::Done,
                ],
            ]);

            let session_id = run_agent_with_provider(
                &store,
                &provider,
                "Use the configured docs MCP echo tool.",
                temp.path(),
                AgentRunOptions::default(),
            )?;
            let events = store.events_for_session(&session_id)?;
            assert!(events.iter().any(|event| {
                event.event_type == "mcp.tool_result"
                    && event.payload["mcp_server"] == "docs"
                    && event.payload["mcp_tool"] == "echo.tool"
                    && event.payload["result"]["content"][0]["text"] == "echo:hello"
            }));
            assert!(events.iter().any(|event| {
                event.event_type == MODEL_RESPONSE_INPUT_ITEM_EVENT
                    && event.payload["call_id"] == "mcp_1"
                    && event.payload["item"]["output"]
                        .as_str()
                        .is_some_and(|output| {
                            output.starts_with("Wall time: ")
                                && output.contains("\"text\":\"hello\"")
                                && !output.contains("structuredContent")
                                && !output.contains("isError")
                        })
            }));
            assert!(events.iter().any(|event| {
                event.event_type == "session.done" && event.payload["result"] == "final"
            }));
            Ok(())
        })
    }

