    #[test]
    fn provider_loop_respects_external_cancel_before_finalizing() -> Result<()> {
        let temp = tempfile::tempdir()?;
        let store = Store::open(temp.path())?;
        let session = store.create_session(None, temp.path())?;
        store.append_event(
            &session.id,
            "session.input",
            serde_json::json!({"text": "cancel me"}),
        )?;
        let provider = CancellingProvider {
            state_dir: temp.path().to_path_buf(),
            session_id: session.id.clone(),
        };

        let result = run_existing_session_with_provider(
            &store,
            &provider,
            &session.id,
            AgentRunOptions::default(),
        );

        assert!(result.is_err());
        let session = store.load_session(&session.id)?.context("session")?;
        assert_eq!(session.status, SessionStatus::Cancelled);
        let events = store.events_for_session(&session.id)?;
        assert!(events
            .iter()
            .any(|event| event.event_type == "session.cancelled"));
        assert!(events.iter().any(|event| {
            event.event_type == CODEX_TURN_ABORTED_EVENT
                && event.payload["reason"] == "interrupted"
                && event.payload["status"] == "cancelled"
        }));
        assert!(!events
            .iter()
            .any(|event| event.event_type == "session.done"));
        let runs = store.runs_for_session(&session.id)?;
        assert_eq!(runs.len(), 1);
        assert_eq!(runs[0].status, "cancelled");
        Ok(())
    }

    #[test]
    fn provider_loop_drains_followup_before_finalizing_text() -> Result<()> {
        let temp = tempfile::tempdir()?;
        let store = Store::open(temp.path())?;
        let session = store.create_session(None, temp.path())?;
        store.append_event(
            &session.id,
            "session.input",
            serde_json::json!({"text": "answer the first prompt"}),
        )?;
        let provider = FollowupBeforeFinalizationProvider {
            state_dir: temp.path().to_path_buf(),
            session_id: session.id.clone(),
            attempts: std::sync::Mutex::new(0),
        };

        let session_id = run_existing_session_with_provider(
            &store,
            &provider,
            &session.id,
            AgentRunOptions::default(),
        )?;

        assert_eq!(session_id, session.id);
        assert_eq!(*provider.attempts.lock().expect("attempts"), 2);
        let events = store.events_for_session(&session.id)?;
        assert!(events.iter().any(|event| {
            event.event_type == "agent.turn_queue_drained"
                && event.payload["phase"] == "before_finalization"
                && event.payload["session_messages"] == 1
        }));
        assert!(events.iter().any(|event| {
            event.event_type == "session.done" && event.payload["result"] == "handled followup"
        }));
        assert!(!events.iter().any(|event| {
            event.event_type == "session.done" && event.payload["result"] == "premature final"
        }));
        Ok(())
    }

