    #[test]
    fn cancellation_cleans_up_background_exec_like_codex_stop() -> Result<()> {
        let temp = tempfile::tempdir()?;
        let store = Store::open(temp.path())?;
        let session = store.create_session(None, temp.path())?;
        append_workspace_context_event(&store, &session)?;
        store.append_event(
            &session.id,
            "session.input",
            serde_json::json!({"text": "start then cancel"}),
        )?;
        let provider = CancelAfterBackgroundExecProvider {
            state_dir: temp.path().to_path_buf(),
            session_id: session.id.clone(),
            ..Default::default()
        };
        let messages = provider_messages_from_events(&store.events_for_session(&session.id)?);

        let result = run_loaded_session_with_provider(
            &store,
            &provider,
            session.clone(),
            messages,
            AgentRunOptions::default(),
        );

        assert!(result.is_err());
        assert!(
            provider.process_id.lock().expect("process id").is_some(),
            "test provider should observe a running exec session before cancelling"
        );
        assert_eq!(
            cleanup_unified_exec_commands_for_session(&session.id),
            0,
            "cancel finalization should already remove background unified exec sessions"
        );
        let session = store.load_session(&session.id)?.context("session")?;
        assert_eq!(session.status, SessionStatus::Cancelled);
        Ok(())
    }

    #[derive(Default)]
    struct CancelAfterBackgroundExecProvider {
        state_dir: std::path::PathBuf,
        session_id: String,
        step: std::sync::Mutex<usize>,
        process_id: std::sync::Mutex<Option<i64>>,
    }

    impl ModelProvider for CancelAfterBackgroundExecProvider {
        fn start_turn(&self, turn: ProviderTurn) -> Result<Vec<ModelEvent>> {
            let mut step = self.step.lock().expect("step lock");
            let events = match *step {
                0 => vec![
                    ModelEvent::ToolCall {
                        call: ToolCall {
                            id: "exec_then_cancel".to_string(),
                            name: "exec_command".to_string(),
                            namespace: None,
                            arguments: serde_json::json!({
                                "cmd": "python3 -u -c \"import time; print('ready', flush=True); time.sleep(10)\"",
                                "tty": true,
                                "yield_time_ms": 100,
                            }),
                        },
                    },
                    ModelEvent::Done,
                ],
                _ => {
                    let content = latest_tool_content(&turn, "exec_command")
                        .context("exec command tool response")?;
                    let marker = "Process running with session ID ";
                    let process_id = content
                        .lines()
                        .find_map(|line| line.strip_prefix(marker))
                        .context("running session id line")?
                        .parse::<i64>()?;
                    *self.process_id.lock().expect("process id lock") = Some(process_id);
                    Store::open(&self.state_dir)?
                        .request_cancel(&self.session_id, "test cancel")?;
                    vec![ModelEvent::Done]
                }
            };
            *step += 1;
            Ok(events)
        }

        fn provider_name(&self) -> &str {
            "cancel-after-background-exec"
        }

        fn model_name(&self) -> &str {
            "cancel-after-background-exec"
        }
    }

    #[derive(Default)]
    struct ExecToolOutputInspectingProvider {
        step: std::sync::Mutex<usize>,
    }

    impl ModelProvider for ExecToolOutputInspectingProvider {
        fn start_turn(&self, turn: ProviderTurn) -> Result<Vec<ModelEvent>> {
            let mut step = self.step.lock().expect("step lock");
            let events = if *step == 0 {
                vec![
                    ModelEvent::ToolCall {
                        call: ToolCall {
                            id: "exec_1".to_string(),
                            name: "exec_command".to_string(),
                            namespace: None,
                            arguments: serde_json::json!({
                                "cmd": "printf codex-tool",
                                "yield_time_ms": 5000,
                            }),
                        },
                    },
                    ModelEvent::Done,
                ]
            } else {
                let content = latest_tool_content(&turn, "exec_command")
                    .context("exec command tool response")?;
                let chunk_id = content
                    .lines()
                    .next()
                    .and_then(|line| line.strip_prefix("Chunk ID: "))
                    .context("exec output should use Codex-style chunk header")?;
                assert_eq!(chunk_id.len(), 6);
                assert!(chunk_id.chars().all(|ch| ch.is_ascii_hexdigit()));
                assert!(
                    content.contains("Wall time: "),
                    "exec output should include wall time: {content}"
                );
                assert!(
                    content.contains("Process exited with code 0"),
                    "exec output should include exit code: {content}"
                );
                assert!(
                    content.contains("Original token count: "),
                    "exec output should include original token count: {content}"
                );
                assert!(
                    content.ends_with("Output:\ncodex-tool"),
                    "exec output should end with terminal output: {content}"
                );
                assert!(
                    serde_json::from_str::<Value>(content).is_err(),
                    "exec output should be model-visible text, not JSON"
                );
                vec![
                    ModelEvent::ToolCall {
                        call: ToolCall {
                            id: "done_after_exec".to_string(),
                            name: "done".to_string(),
                            namespace: None,
                            arguments: serde_json::json!({"result": "command complete"}),
                        },
                    },
                    ModelEvent::Done,
                ]
            };
            *step += 1;
            Ok(events)
        }
    }

    #[derive(Default)]
    struct WriteStdinClosedInspectingProvider {
        step: std::sync::Mutex<usize>,
        process_id: std::sync::Mutex<Option<i64>>,
    }

    impl ModelProvider for WriteStdinClosedInspectingProvider {
        fn start_turn(&self, turn: ProviderTurn) -> Result<Vec<ModelEvent>> {
            let mut step = self.step.lock().expect("step lock");
            let events = match *step {
                0 => vec![
                    ModelEvent::ToolCall {
                        call: ToolCall {
                            id: "exec_non_tty".to_string(),
                            name: "exec_command".to_string(),
                            namespace: None,
                            arguments: serde_json::json!({
                                "cmd": "printf 'ready\\n'; sleep 5",
                                "yield_time_ms": 1000,
                            }),
                        },
                    },
                    ModelEvent::Done,
                ],
                1 => {
                    let content = latest_tool_content(&turn, "exec_command")
                        .context("exec command tool response")?;
                    let marker = "Process running with session ID ";
                    let session_id = content
                        .lines()
                        .find_map(|line| line.strip_prefix(marker))
                        .with_context(|| format!("running session id line in {content:?}"))?
                        .parse::<i64>()?;
                    assert!(session_id >= 1000);
                    *self.process_id.lock().expect("process id lock") = Some(session_id);
                    vec![
                        ModelEvent::ToolCall {
                            call: ToolCall {
                                id: "write_non_tty".to_string(),
                                name: "write_stdin".to_string(),
                                namespace: None,
                                arguments: serde_json::json!({
                                    "session_id": session_id,
                                    "chars": "hello\n",
                                    "yield_time_ms": 50,
                                }),
                            },
                        },
                        ModelEvent::Done,
                    ]
                }
                _ => {
                    let content = latest_tool_content(&turn, "write_stdin")
                        .context("write_stdin tool response")?;
                    assert!(
                        content.contains("write_stdin failed: stdin is closed for this session; rerun exec_command with tty=true to keep stdin open"),
                        "write_stdin failure should be model-visible and recoverable: {content}"
                    );
                    vec![
                        ModelEvent::ToolCall {
                            call: ToolCall {
                                id: "done_after_stdin_gate".to_string(),
                                name: "done".to_string(),
                                namespace: None,
                                arguments: serde_json::json!({"result": "stdin gate matched"}),
                            },
                        },
                        ModelEvent::Done,
                    ]
                }
            };
            *step += 1;
            Ok(events)
        }
    }

    #[derive(Default)]
    struct CrossTurnBackgroundExecProvider {
        step: std::sync::Mutex<usize>,
        process_id: std::sync::Mutex<Option<i64>>,
    }

    impl ModelProvider for CrossTurnBackgroundExecProvider {
        fn start_turn(&self, turn: ProviderTurn) -> Result<Vec<ModelEvent>> {
            let mut step = self.step.lock().expect("step lock");
            let events = match *step {
                0 => vec![
                    ModelEvent::ToolCall {
                        call: ToolCall {
                            id: "exec_cross_turn".to_string(),
                            name: "exec_command".to_string(),
                            namespace: None,
                            arguments: serde_json::json!({
                                "cmd": "python3 -u -c \"import sys; print('ready', flush=True); [print('echo:' + line.strip(), flush=True) for line in sys.stdin]\"",
                                "tty": true,
                                "yield_time_ms": 1000,
                            }),
                        },
                    },
                    ModelEvent::Done,
                ],
                1 => {
                    let content = latest_tool_content(&turn, "exec_command")
                        .context("exec command tool response")?;
                    assert!(
                        content.contains("Output:\nready"),
                        "background command should return initial output: {content}"
                    );
                    let marker = "Process running with session ID ";
                    let session_id = content
                        .lines()
                        .find_map(|line| line.strip_prefix(marker))
                        .context("running session id line")?
                        .parse::<i64>()?;
                    *self.process_id.lock().expect("process id lock") = Some(session_id);
                    vec![
                        ModelEvent::ToolCall {
                            call: ToolCall {
                                id: "done_after_background_exec".to_string(),
                                name: "done".to_string(),
                                namespace: None,
                                arguments: serde_json::json!({
                                    "result": "background command started",
                                }),
                            },
                        },
                        ModelEvent::Done,
                    ]
                }
                2 => {
                    let session_id = self
                        .process_id
                        .lock()
                        .expect("process id lock")
                        .context("process id from first turn")?;
                    vec![
                        ModelEvent::ToolCall {
                            call: ToolCall {
                                id: "write_cross_turn".to_string(),
                                name: "write_stdin".to_string(),
                                namespace: None,
                                arguments: serde_json::json!({
                                    "session_id": session_id,
                                    "chars": "after-turn\n",
                                    "yield_time_ms": 1000,
                                }),
                            },
                        },
                        ModelEvent::Done,
                    ]
                }
                _ => {
                    let content = latest_tool_content(&turn, "write_stdin")
                        .context("write_stdin tool response")?;
                    assert!(
                        content.contains("echo:after-turn"),
                        "follow-up should reach the same background session: {content}"
                    );
                    vec![
                        ModelEvent::ToolCall {
                            call: ToolCall {
                                id: "done_after_cross_turn_stdin".to_string(),
                                name: "done".to_string(),
                                namespace: None,
                                arguments: serde_json::json!({
                                    "result": "background command survived",
                                }),
                            },
                        },
                        ModelEvent::Done,
                    ]
                }
            };
            *step += 1;
            Ok(events)
        }
    }

    #[test]
    fn streamed_apply_patch_custom_input_deltas_emit_progress_only() -> Result<()> {
        let temp = tempfile::tempdir()?;
        let store = Store::open(temp.path())?;
        let provider = StreamingPatchProgressProvider::default();
        let session_id = run_agent_with_provider(
            &store,
            &provider,
            "stream a patch",
            temp.path(),
            AgentRunOptions::default(),
        )?;

        assert_eq!(
            std::fs::read_to_string(temp.path().join("streamed.txt"))?,
            "hello\n"
        );
        let events = store.events_for_session(&session_id)?;
        let updated = events
            .iter()
            .find(|event| event.event_type == "patch.updated")
            .context("patch updated event")?;
        assert_eq!(updated.payload["tool_call_id"], "patch_stream");
        assert_eq!(updated.payload["changes"][0]["path"], "streamed.txt");
        assert_eq!(updated.payload["changes"][0]["kind"], "added");
        assert!(events.iter().any(|event| {
            event.event_type == "patch.finished"
                && event.payload["tool_call_id"] == "patch_stream"
                && event.payload["status"] == "completed"
        }));
        Ok(())
    }

    #[derive(Default)]
    struct StreamingPatchProgressProvider {
        step: std::sync::Mutex<usize>,
    }

    impl ModelProvider for StreamingPatchProgressProvider {
        fn start_turn(&self, _turn: ProviderTurn) -> Result<Vec<ModelEvent>> {
            Ok(vec![ModelEvent::Done])
        }

        fn stream_turn(
            &self,
            turn: ProviderTurn,
            on_event: &mut dyn FnMut(ModelEvent) -> Result<()>,
        ) -> Result<()> {
            let mut step = self.step.lock().expect("step lock");
            if *step == 0 {
                let patch = "*** Begin Patch\n*** Add File: streamed.txt\n+hello\n*** End Patch";
                on_event(ModelEvent::CustomToolCallInputDelta {
                    call_id: "patch_stream".to_string(),
                    name: "apply_patch".to_string(),
                    delta: "*** Begin Patch\n*** Add File: streamed.txt\n".to_string(),
                })?;
                on_event(ModelEvent::CustomToolCallInputDelta {
                    call_id: "patch_stream".to_string(),
                    name: "apply_patch".to_string(),
                    delta: "+hello\n*** End Patch".to_string(),
                })?;
                on_event(ModelEvent::ToolCall {
                    call: ToolCall {
                        id: "patch_stream".to_string(),
                        name: "apply_patch".to_string(),
                        namespace: None,
                        arguments: Value::String(patch.to_string()),
                    },
                })?;
                on_event(ModelEvent::Done)?;
            } else {
                let content =
                    latest_tool_content(&turn, "apply_patch").context("apply_patch output")?;
                assert!(content.contains("Success. Updated the following files:"));
                on_event(ModelEvent::ToolCall {
                    call: ToolCall {
                        id: "done_after_streamed_patch".to_string(),
                        name: "done".to_string(),
                        namespace: None,
                        arguments: serde_json::json!({"result": "streamed patch complete"}),
                    },
                })?;
                on_event(ModelEvent::Done)?;
            }
            *step += 1;
            Ok(())
        }
    }

    fn latest_tool_content<'a>(turn: &'a ProviderTurn, name: &str) -> Option<&'a str> {
        turn.messages.iter().rev().find_map(|message| {
            if message.get("name").and_then(Value::as_str) == Some(name) {
                message.get("content").and_then(Value::as_str)
            } else {
                None
            }
        })
    }

