    #[test]
    fn multi_agent_v1_skill_and_mention_items_are_not_ordinary_user_text() -> Result<()> {
        let temp = tempfile::tempdir()?;
        let skill_path = temp.path().join("skills").join("Docs").join("SKILL.md");
        std::fs::create_dir_all(skill_path.parent().context("skill parent")?)?;
        std::fs::write(&skill_path, "Use the typed skill body.")?;

        let skill_input = parse_collab_input(
            None,
            Some(&json!([
                {"type": "skill", "name": "Docs", "path": skill_path.display().to_string()}
            ])),
        )
        .map_err(anyhow::Error::msg)?;
        assert!(skill_input.preview.contains("[skill:$Docs]"));
        assert!(skill_input.content.as_array().is_some_and(Vec::is_empty));
        let skill_payload = collab_input_event_payload(&skill_input);
        assert!(skill_payload["skill_context_messages"]
            .as_array()
            .is_some_and(|messages| messages.len() == 1));
        let skill_messages = session_event_user_messages(&skill_payload);
        assert_eq!(skill_messages.len(), 1);
        assert_eq!(
            skill_messages[0].get("role").and_then(Value::as_str),
            Some("user")
        );
        assert!(message_content_text(&skill_messages[0]).contains("<skill>\n<name>Docs</name>"));
        assert!(message_content_text(&skill_messages[0]).contains("Use the typed skill body."));
        std::fs::write(&skill_path, "This later disk change should not replay.")?;
        let stable_skill_messages = session_event_user_messages(&skill_payload);
        assert!(
            message_content_text(&stable_skill_messages[0]).contains("Use the typed skill body.")
        );
        assert!(!message_content_text(&stable_skill_messages[0])
            .contains("This later disk change should not replay."));

        let mention_input = parse_collab_input(
            None,
            Some(&json!([
                {"type": "mention", "name": "Calendar", "path": "app://calendar"},
                {"type": "mention", "name": "Plugin", "path": "plugin://notes@example"}
            ])),
        )
        .map_err(anyhow::Error::msg)?;
        assert!(mention_input
            .preview
            .contains("[mention:$Calendar](app://calendar)"));
        assert!(mention_input
            .preview
            .contains("[mention:$Plugin](plugin://notes@example)"));
        assert!(mention_input.content.as_array().is_some_and(Vec::is_empty));
        let mention_payload = collab_input_event_payload(&mention_input);
        assert!(mention_payload.get("skill_context_messages").is_none());
        assert!(mention_payload.get("mention_context_messages").is_none());
        assert_eq!(mention_payload["app_connector_ids"], json!(["calendar"]));
        assert_eq!(
            mention_payload["plugin_mentions"][0]["path"],
            "plugin://notes@example"
        );
        assert!(mention_payload["plugin_mentions"]
            .as_array()
            .is_some_and(|mentions| mentions.len() == 1));
        assert_eq!(mention_payload["items"][0]["path"], "app://calendar");
        assert_eq!(
            mention_payload["items"][1]["path"],
            "plugin://notes@example"
        );
        let mention_messages = session_event_user_messages(&mention_payload);
        assert!(mention_messages.is_empty());
        Ok(())
    }

    #[test]
    fn multi_agent_v1_spawn_preserves_typed_items_for_child_replay_like_codex() -> Result<()> {
        let temp = tempfile::tempdir()?;
        let app_home = create_empty_browser_use_terminal_home(temp.path())?;
        let store = Store::open(temp.path())?;
        let session = store.create_session(None, temp.path())?;
        let provider = FakeProvider::default();
        let missing_image_path = temp.path().join("missing.png");
        let skill_path = temp.path().join("skills").join("Docs").join("SKILL.md");
        std::fs::create_dir_all(skill_path.parent().context("skill parent")?)?;
        std::fs::write(&skill_path, "Use the internal docs workflow.")?;
        let call = ToolCall {
            id: "spawn_v1_items".to_string(),
            name: "spawn_agent".to_string(),
            namespace: Some("multi_agent_v1".to_string()),
            arguments: serde_json::json!({
                "agent_type": "explorer",
                "items": [
                    {"type": "text", "text": "inspect the screenshot"},
                    {"type": "image", "image_url": "data:image/png;base64,abc", "detail": "high"},
                    {"type": "local_image", "path": missing_image_path.display().to_string()},
                    {"type": "skill", "name": "Docs", "path": skill_path.display().to_string()},
                    {"type": "mention", "name": "Calendar", "path": "app://calendar"}
                ]
            }),
        };

        with_browser_use_terminal_home(&app_home, || {
            dispatch_spawn_agent_tool(
                &store,
                &provider,
                &session,
                &call,
                &AgentRunOptions::default(),
                &None,
            )
        })?;

        let child = store
            .list_child_agents(&session.id)?
            .into_iter()
            .next()
            .context("child agent")?;
        assert!(child.agent_path.is_none());
        let child_events = store.events_for_session(&child.child_session_id)?;
        let input = child_events
            .iter()
            .find(|event| event.event_type == "session.input")
            .context("session.input")?;
        assert_eq!(input.payload["items"][0]["type"], "text");
        assert!(input.payload["text"]
            .as_str()
            .unwrap_or_default()
            .contains("[image]"));
        assert!(input.payload["text"]
            .as_str()
            .unwrap_or_default()
            .contains("[skill:$Docs]"));
        assert!(input.payload["text"]
            .as_str()
            .unwrap_or_default()
            .contains("[mention:$Calendar](app://calendar)"));
        let content = input.payload["content"].as_array().context("content")?;
        assert!(content.iter().any(|part| {
            part["type"] == "input_image" && part["image_url"] == "data:image/png;base64,abc"
        }));
        assert!(content.iter().any(|part| {
            part["type"] == "input_text"
                && part["text"]
                    .as_str()
                    .unwrap_or_default()
                    .contains("Codex could not read the local image")
        }));
        assert!(!content.iter().any(|part| {
            part["type"] == "input_text"
                && part["text"]
                    .as_str()
                    .unwrap_or_default()
                    .contains("[skill:$Docs]")
        }));
        assert!(!content.iter().any(|part| {
            part["type"] == "input_text"
                && part["text"]
                    .as_str()
                    .unwrap_or_default()
                    .contains("[mention:$Calendar]")
        }));
        assert!(input.payload["skill_context_messages"]
            .as_array()
            .is_some_and(|messages| messages.len() == 1));
        assert!(input.payload.get("mention_context_messages").is_none());
        assert_eq!(input.payload["app_connector_ids"], json!(["calendar"]));
        std::fs::write(&skill_path, "This later rewrite should not replay.")?;

        let messages = provider_messages_from_events(&child_events);
        assert!(messages.iter().any(|message| {
            message.get("role").and_then(Value::as_str) == Some("user")
                && message
                    .get("content")
                    .and_then(Value::as_array)
                    .is_some_and(|parts| {
                        parts.iter().any(|part| {
                            part["type"] == "input_image"
                                && part["image_url"] == "data:image/png;base64,abc"
                        })
                    })
        }));
        assert!(messages.iter().any(|message| {
            message.get("role").and_then(Value::as_str) == Some("user")
                && message_content_text(message).contains("<skill>\n<name>Docs</name>")
                && message_content_text(message).contains("Use the internal docs workflow.")
        }));
        assert!(!messages.iter().any(is_mention_context_message));
        assert!(!messages.iter().any(|message| message_content_text(message)
            .contains("This later rewrite should not replay.")));
        let model_text = messages
            .iter()
            .map(message_content_text)
            .collect::<Vec<_>>()
            .join("\n");
        assert!(!model_text.contains("[mention:$Calendar]"));
        assert!(!model_text.contains("app://calendar"));
        Ok(())
    }

    #[test]
    fn multi_agent_v1_send_input_persists_typed_followup_without_string_mailbox() -> Result<()> {
        let temp = tempfile::tempdir()?;
        let store = Store::open(temp.path())?;
        let parent = store.create_session(None, temp.path())?;
        let child = store.create_child_session(
            &parent.id,
            temp.path(),
            Some("/root/typed_child"),
            Some("typed_child"),
            Some("explorer"),
        )?;
        let provider = FakeProvider::default();
        let skill_path = temp.path().join("skills").join("Review").join("SKILL.md");
        std::fs::create_dir_all(skill_path.parent().context("skill parent")?)?;
        std::fs::write(&skill_path, "Always check the review checklist.")?;
        let call = ToolCall {
            id: "send_v1_items".to_string(),
            name: "send_input".to_string(),
            namespace: Some("multi_agent_v1".to_string()),
            arguments: serde_json::json!({
                "target": child.id,
                "items": [
                    {"type": "text", "text": "look at this"},
                    {"type": "image", "image_url": "data:image/png;base64,abc"},
                    {"type": "skill", "name": "Review", "path": skill_path.display().to_string()},
                    {"type": "mention", "name": "Notes", "path": "plugin://notes@example"}
                ]
            }),
        };

        dispatch_send_input_v1_tool(
            &store,
            &provider,
            &parent,
            &call,
            &AgentRunOptions::default(),
        )?;

        assert!(store.messages_for_agent(&child.id)?.is_empty());
        let child_events = store.events_for_session(&child.id)?;
        let followup = child_events
            .iter()
            .find(|event| event.event_type == "session.followup")
            .context("session.followup")?;
        assert_eq!(followup.payload["items"][1]["type"], "image");
        assert!(followup.payload["content"]
            .as_array()
            .unwrap()
            .iter()
            .any(|part| part["type"] == "input_image"
                && part["image_url"] == "data:image/png;base64,abc"));
        assert!(followup.payload["skill_context_messages"]
            .as_array()
            .is_some_and(|messages| messages.len() == 1));
        assert!(followup.payload.get("mention_context_messages").is_none());
        assert_eq!(
            followup.payload["plugin_mentions"][0]["path"],
            "plugin://notes@example"
        );
        std::fs::remove_file(&skill_path)?;
        let messages = provider_messages_from_events(&child_events);
        assert!(messages.iter().any(|message| {
            message.get("role").and_then(Value::as_str) == Some("user")
                && message
                    .get("content")
                    .and_then(Value::as_array)
                    .is_some_and(|parts| parts.iter().any(|part| part["type"] == "input_image"))
        }));
        assert!(messages.iter().any(|message| {
            message.get("role").and_then(Value::as_str) == Some("user")
                && message_content_text(message).contains("<skill>\n<name>Review</name>")
                && message_content_text(message).contains("Always check the review checklist.")
        }));
        assert!(!messages.iter().any(is_mention_context_message));
        let model_text = messages
            .iter()
            .map(message_content_text)
            .collect::<Vec<_>>()
            .join("\n");
        assert!(!model_text.contains("[mention:$Notes]"));
        assert!(!model_text.contains("plugin://notes@example"));
        Ok(())
    }

