    fn write_mock_codex_plugin_bundle(app_home: &Path) -> Result<PathBuf> {
        let plugin_root = app_home
            .join(BROWSER_USE_TERMINAL_PLUGIN_CACHE_DIR)
            .join("test")
            .join("sample")
            .join("local");
        std::fs::create_dir_all(plugin_root.join(".browser-use-plugin"))?;
        std::fs::create_dir_all(plugin_root.join("skills").join("sample-search"))?;
        std::fs::write(
            plugin_root.join(".browser-use-plugin").join("plugin.json"),
            serde_json::json!({
                "name": "sample",
                "description": "Inspect sample data",
            })
            .to_string(),
        )?;
        std::fs::write(
            plugin_root
                .join("skills")
                .join("sample-search")
                .join("SKILL.md"),
            "Use sample search.",
        )?;
        std::fs::write(
            plugin_root.join(".mcp.json"),
            serde_json::json!({
                "mcpServers": {
                    "sample": {"command": "sample-mcp"}
                }
            })
            .to_string(),
        )?;
        std::fs::write(
            plugin_root.join(".app.json"),
            serde_json::json!({
                "apps": {
                    "calendar": {"id": "calendar"}
                }
            })
            .to_string(),
        )?;
        std::fs::write(
            app_home.join("config.toml"),
            r#"
[features]
plugins = true

[plugins."sample@test"]
enabled = true
"#,
        )?;
        Ok(plugin_root)
    }

